1	import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
2	import fp from 'fastify-plugin';
3	import jwt from '@fastify/jwt';
4	import { eq, and } from 'drizzle-orm';
5	import { sessions } from '@studioops/db/schema';
6	
7	declare module 'fastify' {
8	  interface FastifyInstance {
9	    authenticate: (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
10	    optionalAuthenticate: (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
11	  }
12	}
13	
14	declare module '@fastify/jwt' {
15	  interface FastifyJWT {
16	    payload: { sub: string; role: string; jti: string };
17	    user: { sub: string; role: string; jti: string };
18	  }
19	}
20	
21	interface AuthPluginOptions {
22	  jwtSecret: string;
23	}
24	
25	async function authPlugin(fastify: FastifyInstance, opts: AuthPluginOptions) {
26	  await fastify.register(jwt, {
27	    secret: opts.jwtSecret,
28	    sign: {
29	      expiresIn: '30m',
30	    },
31	  });
32	
33	  fastify.decorate('authenticate', async function (request: FastifyRequest, reply: FastifyReply) {
34	    try {
35	      await request.jwtVerify();
36	    } catch (err) {
37	      return reply.status(401).send({
38	        error: 'UNAUTHORIZED',
39	        message: 'Invalid or expired token',
40	      });
41	    }
42	
43	    // Validate session: look up by jti, reject if revoked or expired
44	    const jti = request.user.jti;
45	    if (jti) {
46	      try {
47	        const [session] = await fastify.db
48	          .select()
49	          .from(sessions)
50	          .where(eq(sessions.tokenJti, jti))
51	          .limit(1);
52	
53	        if (!session) {
54	          return reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Session not found' });
55	        }
56	
57	        if (session.revoked) {
58	          return reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Session has been revoked' });
59	        }
60	
61	        if (session.absoluteExpiresAt < new Date()) {
62	          return reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Session expired' });
63	        }
64	
65	        // Update last activity for sliding session tracking
66	        await fastify.db
67	          .update(sessions)
68	          .set({ lastActivityAt: new Date() })
69	          .where(eq(sessions.id, session.id));
70	      } catch (err) {
71	        request.log.error({ err }, 'Session validation failed');
72	        return reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Session validation failed' });
73	      }
74	    }
75	  });
76	
77	  // Optional authenticate: validates session if token present, but allows guest access (no token = no user, no error)
78	  fastify.decorate('optionalAuthenticate', async function (request: FastifyRequest, _reply: FastifyReply) {
79	    try {
80	      await request.jwtVerify();
81	    } catch {
82	      // No token or invalid token — guest access, not an error
83	      return;
84	    }
85	
86	    // Token valid — now validate session (same checks as authenticate)
87	    const jti = request.user?.jti;
88	    if (jti) {
89	      try {
90	        const [session] = await fastify.db
91	          .select()
92	          .from(sessions)
93	          .where(eq(sessions.tokenJti, jti))
94	          .limit(1);
95	
96	        if (!session || session.revoked || session.absoluteExpiresAt < new Date()) {
97	          // Session invalid — treat as unauthenticated guest (clear user)
98	          (request as any).user = undefined;
99	          return;
100	        }
101	
102	        await fastify.db
103	          .update(sessions)
104	          .set({ lastActivityAt: new Date() })
105	          .where(eq(sessions.id, session.id));
106	      } catch {
107	        // Session check failed — treat as guest
108	        (request as any).user = undefined;
109	      }
110	    }
111	  });
112	}
113	
114	export default fp(authPlugin, {
115	  name: 'auth',
116	  dependencies: ['database'],
117	  fastify: '5.x',
118	});
