1	import { FastifyInstance } from 'fastify';
2	import { validateDateRange, type DashboardFilters } from '../../core/domain/analytics';
3	import { DrizzleAnalyticsRepository } from '../../infrastructure/persistence/analytics-repository';
4	import { generateCsv, generateExcel } from '../../infrastructure/export/export-service';
5	
6	export default async function analyticsRoutes(fastify: FastifyInstance) {
7	  const analyticsRepo = new DrizzleAnalyticsRepository(fastify.db);
8	
9	  // GET /analytics/dashboard
10	  fastify.get('/dashboard', {
11	    preHandler: [fastify.authenticate, fastify.authorize('analytics', 'view')],
12	  }, async (request, reply) => {
13	    const query = request.query as { from?: string; to?: string; orgId?: string; eventType?: string };
14	
15	    const now = new Date();
16	    const from = query.from ? new Date(query.from) : new Date(now.getTime() - 30 * 86400000);
17	    const to = query.to ? new Date(query.to) : now;
18	
19	    const dateValidation = validateDateRange(from, to);
20	    if (!dateValidation.valid) {
21	      return reply.status(422).send({ error: 'INVALID_DATE_RANGE', message: dateValidation.error });
22	    }
23	
24	    // Org scoping
25	    let orgId = query.orgId;
26	    if (request.user.role === 'operations') {
27	      if (orgId && request.authContext?.orgScope && !request.authContext.orgScope.includes(orgId)) {
28	        return reply.status(403).send({ error: 'FORBIDDEN_ORG_ACCESS', message: 'Organization not in your scope' });
29	      }
30	    }
31	
32	    const filters: DashboardFilters = { from, to, orgId, eventType: query.eventType };
33	    // Admin: undefined orgScope (sees all). Non-admin: always an array (possibly empty = sees nothing).
34	    const orgScope = request.user.role === 'administrator' ? undefined : (request.authContext?.orgScope ?? []);
35	
36	    const payload = await analyticsRepo.getDashboard(filters, orgScope);
37	
38	    return reply.status(200).send(payload);
39	  });
40	
41	  // POST /analytics/export (rules-engine enforced cooldown)
42	  fastify.post('/export', {
43	    preHandler: [fastify.authenticate, fastify.authorize('analytics', 'export'), fastify.enforceQuota('export_cooldown')],
44	  }, async (request, reply) => {
45	    const body = request.body as { format: string; filters?: { from?: string; to?: string; orgId?: string; eventType?: string } };
46	
47	    if (!body.format || !['csv', 'xlsx'].includes(body.format)) {
48	      return reply.status(422).send({ error: 'INVALID_EXPORT_FORMAT', message: 'Format must be csv or xlsx', accepted: ['csv', 'xlsx'] });
49	    }
50	
51	    const now = new Date();
52	    const from = body.filters?.from ? new Date(body.filters.from) : new Date(now.getTime() - 30 * 86400000);
53	    const to = body.filters?.to ? new Date(body.filters.to) : now;
54	
55	    const dateValidation = validateDateRange(from, to);
56	    if (!dateValidation.valid) {
57	      return reply.status(422).send({ error: 'INVALID_DATE_RANGE', message: dateValidation.error });
58	    }
59	
60	    const filters: DashboardFilters = { from, to, orgId: body.filters?.orgId, eventType: body.filters?.eventType };
61	    const orgScope = request.user.role === 'administrator' ? undefined : (request.authContext?.orgScope ?? []);
62	
63	    const payload = await analyticsRepo.getDashboard(filters, orgScope);
64	
65	    // Cooldown is enforced by rules-engine preHandler (export_cooldown rule)
66	    const dateStr = now.toISOString().split('T')[0];
67	
68	    if (body.format === 'csv') {
69	      const csv = generateCsv(payload);
70	      return reply
71	        .header('Content-Type', 'text/csv')
72	        .header('Content-Disposition', `attachment; filename="analytics-${dateStr}.csv"`)
73	        .send(csv);
74	    }
75	
76	    if (body.format === 'xlsx') {
77	      const buffer = await generateExcel(payload);
78	      return reply
79	        .header('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')
80	        .header('Content-Disposition', `attachment; filename="analytics-${dateStr}.xlsx"`)
81	        .send(buffer);
82	    }
83	  });
84	}
