1	import { eq, and, gte, lte, inArray, desc, sql } from 'drizzle-orm';
2	import { events, registrations, analyticsSnapshots } from '@studioops/db/schema';
3	import { safeRatio, computeFilterHash, type DashboardFilters, type DashboardPayload } from '../../core/domain/analytics';
4	import type { PostgresJsDatabase } from 'drizzle-orm/postgres-js';
5	type Database = PostgresJsDatabase<any>;
6	
7	const CACHE_TTL_MS = 15 * 60 * 1000; // 15 minutes
8	
9	export class DrizzleAnalyticsRepository {
10	  constructor(private db: Database) {}
11	
12	  async getDashboard(filters: DashboardFilters, orgScope?: string[]): Promise<DashboardPayload> {
13	    const filterHash = computeFilterHash(filters, orgScope);
14	
15	    // Check cache (partitioned by org scope via hash)
16	    const cached = await this.db.select().from(analyticsSnapshots)
17	      .where(and(
18	        eq(analyticsSnapshots.filterHash, filterHash),
19	        eq(analyticsSnapshots.snapshotType, 'dashboard'),
20	      ))
21	      .orderBy(desc(analyticsSnapshots.createdAt))
22	      .limit(1);
23	
24	    if (cached.length > 0) {
25	      const age = Date.now() - cached[0].createdAt.getTime();
26	      if (age < CACHE_TTL_MS) {
27	        return cached[0].payload as DashboardPayload;
28	      }
29	    }
30	
31	    // Compute fresh metrics
32	    const payload = await this.computeMetrics(filters, orgScope);
33	
34	    // Cache the snapshot
35	    await this.db.insert(analyticsSnapshots).values({
36	      snapshotType: 'dashboard',
37	      filterHash,
38	      payload,
39	      periodStart: filters.from,
40	      periodEnd: filters.to,
41	    });
42	
43	    return payload;
44	  }
45	
46	  private async computeMetrics(filters: DashboardFilters, orgScope?: string[]): Promise<DashboardPayload> {
47	    const eventConditions: any[] = [
48	      gte(events.scheduledAt, filters.from),
49	      lte(events.scheduledAt, filters.to),
50	    ];
51	
52	    if (filters.orgId) {
53	      eventConditions.push(eq(events.orgId, filters.orgId));
54	    } else if (orgScope !== undefined) {
55	      // orgScope is defined = non-admin user; enforce even if empty (empty = zero results)
56	      if (orgScope.length > 0) {
57	        eventConditions.push(inArray(events.orgId, orgScope));
58	      } else {
59	        // Empty org scope: user has no assigned orgs → return nothing
60	        eventConditions.push(sql`false`);
61	      }
62	    }
63	    // orgScope === undefined = admin: no org filter (sees all)
64	
65	    if (filters.eventType) {
66	      eventConditions.push(eq(events.eventType, filters.eventType));
67	    }
68	
69	    const eventWhere = and(...eventConditions);
70	
71	    // 1. Event popularity by type
72	    const popularityRows = await this.db
73	      .select({ eventType: events.eventType, count: sql<number>`count(*)::int` })
74	      .from(events)
75	      .where(eventWhere)
76	      .groupBy(events.eventType)
77	      .orderBy(sql`count(*) DESC`);
78	
79	    // 2. Get all event IDs in range for registration queries
80	    const eventIds = await this.db.select({ id: events.id }).from(events).where(eventWhere);
81	    const ids = eventIds.map(e => e.id);
82	
83	    let conversionFunnel = { stages: ['registered', 'confirmed', 'attended'], counts: [0, 0, 0] };
84	    let attendanceRateData = { labels: ['Attended', 'No-Show'], rates: [0, 0] };
85	    let cancellationRateData = { labels: ['Active', 'Cancelled'], rates: [0, 0] };
86	
87	    if (ids.length > 0) {
88	      // 3. Registration funnel
89	      const regCounts = await this.db
90	        .select({ status: registrations.status, count: sql<number>`count(*)::int` })
91	        .from(registrations)
92	        .where(inArray(registrations.eventId, ids))
93	        .groupBy(registrations.status);
94	
95	      const statusMap = new Map(regCounts.map(r => [r.status, r.count]));
96	      const totalRegs = Array.from(statusMap.values()).reduce((a, b) => a + b, 0);
97	      const confirmed = (statusMap.get('confirmed') ?? 0) + (statusMap.get('attended') ?? 0) + (statusMap.get('no_show') ?? 0);
98	      const attended = statusMap.get('attended') ?? 0;
99	      const cancelled = statusMap.get('cancelled') ?? 0;
100	      const noShow = statusMap.get('no_show') ?? 0;
101	
102	      conversionFunnel = {
103	        stages: ['registered', 'confirmed', 'attended'],
104	        counts: [totalRegs, confirmed, attended],
105	      };
106	
107	      attendanceRateData = {
108	        labels: ['Attended', 'No-Show'],
109	        rates: [
110	          safeRatio(attended, confirmed),
111	          safeRatio(noShow, confirmed),
112	        ],
113	      };
114	
115	      cancellationRateData = {
116	        labels: ['Active', 'Cancelled'],
117	        rates: [
118	          safeRatio(totalRegs - cancelled, totalRegs),
119	          safeRatio(cancelled, totalRegs),
120	        ],
121	      };
122	    }
123	
124	    // 4. Channel distribution
125	    const channelRows = await this.db
126	      .select({ channel: events.channel, count: sql<number>`count(*)::int` })
127	      .from(events)
128	      .where(eventWhere)
129	      .groupBy(events.channel)
130	      .orderBy(sql`count(*) DESC`);
131	
132	    // 5. Tag distribution — enforces same org scope as all other queries
133	    let tagRows: any[] = [];
134	    try {
135	      if (filters.orgId) {
136	        tagRows = await this.db.execute(
137	          sql`SELECT unnest(tags) as tag, count(*)::int as count FROM events WHERE scheduled_at >= ${filters.from} AND scheduled_at <= ${filters.to} AND org_id = ${filters.orgId} GROUP BY tag ORDER BY count DESC LIMIT 20`,
138	        ) as any[];
139	      } else if (orgScope !== undefined) {
140	        if (orgScope.length > 0) {
141	          tagRows = await this.db.execute(
142	            sql`SELECT unnest(tags) as tag, count(*)::int as count FROM events WHERE scheduled_at >= ${filters.from} AND scheduled_at <= ${filters.to} AND org_id = ANY(${orgScope}) GROUP BY tag ORDER BY count DESC LIMIT 20`,
143	          ) as any[];
144	        }
145	        // else: empty orgScope = zero results (tagRows stays empty)
146	      } else {
147	        // orgScope undefined = admin: no org filter
148	        tagRows = await this.db.execute(
149	          sql`SELECT unnest(tags) as tag, count(*)::int as count FROM events WHERE scheduled_at >= ${filters.from} AND scheduled_at <= ${filters.to} GROUP BY tag ORDER BY count DESC LIMIT 20`,
150	        ) as any[];
151	      }
152	    } catch {
153	      tagRows = [];
154	    }
155	
156	    return {
157	      generatedAt: new Date().toISOString(),
158	      filters: {
159	        from: filters.from.toISOString(),
160	        to: filters.to.toISOString(),
161	        orgId: filters.orgId,
162	        eventType: filters.eventType,
163	      },
164	      popularity: {
165	        labels: popularityRows.map(r => r.eventType),
166	        data: popularityRows.map(r => r.count),
167	      },
168	      conversionFunnel,
169	      attendanceRate: attendanceRateData,
170	      cancellationRate: cancellationRateData,
171	      channelDistribution: {
172	        labels: channelRows.map(r => r.channel),
173	        counts: channelRows.map(r => r.count),
174	      },
175	      tagDistribution: {
176	        labels: (tagRows as any[]).map(r => r.tag),
177	        counts: (tagRows as any[]).map(r => r.count),
178	      },
179	    };
180	  }
181	}
