1	import { FastifyInstance } from 'fastify';
2	import { DrizzleCleansingRepository } from '../../infrastructure/persistence/cleansing-repository';
3	import { DrizzleOfferingRepository } from '../../infrastructure/persistence/offering-repository';
4	
5	export default async function dedupRoutes(fastify: FastifyInstance) {
6	  const cleansingRepo = new DrizzleCleansingRepository(fastify.db);
7	  const offeringRepo = new DrizzleOfferingRepository(fastify.db);
8	
9	  // GET /dedup/queue
10	  fastify.get('/queue', {
11	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
12	  }, async (request, reply) => {
13	    const query = request.query as { status?: string; recordType?: string; page?: string; limit?: string };
14	    const page = Math.max(1, parseInt(query.page || '1', 10));
15	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
16	
17	    const result = await cleansingRepo.listCandidates({
18	      status: query.status || 'pending',
19	      recordType: query.recordType,
20	      page,
21	      limit,
22	    });
23	
24	    return reply.status(200).send({
25	      data: result.data,
26	      meta: { page, limit, total: result.total, totalPages: Math.ceil(result.total / limit) },
27	    });
28	  });
29	
30	  // GET /dedup/:candidateId
31	  fastify.get('/:candidateId', {
32	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
33	  }, async (request, reply) => {
34	    const { candidateId } = request.params as { candidateId: string };
35	    const candidate = await cleansingRepo.findCandidateById(candidateId);
36	    if (!candidate) {
37	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
38	    }
39	
40	    // Load both records for side-by-side comparison
41	    let recordA = null;
42	    let recordB = null;
43	    if (candidate.recordType === 'offering') {
44	      recordA = await offeringRepo.findByIdWithAddons(candidate.recordAId);
45	      recordB = await offeringRepo.findByIdWithAddons(candidate.recordBId);
46	
47	      // Org-scope check for non-admin users
48	      if (request.user.role !== 'administrator' && recordA) {
49	        const orgScope = request.authContext?.orgScope ?? [];
50	        if (!orgScope.includes(recordA.orgId)) {
51	          return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
52	        }
53	      }
54	    }
55	
56	    return reply.status(200).send({ candidate, recordA, recordB });
57	  });
58	
59	  // POST /dedup/:candidateId/merge
60	  fastify.post('/:candidateId/merge', {
61	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'merge')],
62	  }, async (request, reply) => {
63	    const { candidateId } = request.params as { candidateId: string };
64	    const { survivingRecordId, mergedRecordId } = request.body as { survivingRecordId: string; mergedRecordId: string };
65	
66	    if (!survivingRecordId || !mergedRecordId) {
67	      return reply.status(400).send({ error: 'VALIDATION_ERROR', message: 'survivingRecordId and mergedRecordId are required' });
68	    }
69	
70	    if (survivingRecordId === mergedRecordId) {
71	      return reply.status(422).send({ error: 'SELF_MERGE_NOT_ALLOWED', message: 'Cannot merge a record with itself' });
72	    }
73	
74	    const candidate = await cleansingRepo.findCandidateById(candidateId);
75	    if (!candidate) {
76	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
77	    }
78	
79	    if (candidate.status !== 'pending') {
80	      return reply.status(409).send({ error: 'CANDIDATE_ALREADY_RESOLVED', message: `Candidate is already ${candidate.status}`, currentStatus: candidate.status });
81	    }
82	
83	    // Verify records exist and belong to same org
84	    if (candidate.recordType === 'offering') {
85	      const recordA = await offeringRepo.findById(survivingRecordId);
86	      const recordB = await offeringRepo.findById(mergedRecordId);
87	
88	      if (!recordA || !recordB) {
89	        return reply.status(404).send({ error: 'RECORD_NOT_FOUND', message: 'One or both records not found' });
90	      }
91	
92	      if (recordA.orgId !== recordB.orgId) {
93	        return reply.status(422).send({ error: 'ORG_MISMATCH', message: 'Records belong to different organizations' });
94	      }
95	
96	      // Build provenance
97	      const provenance = {
98	        original_creators: [
99	          { user_id: recordB.merchantId, created_at: recordB.createdAt, org_id: recordB.orgId },
100	        ],
101	        merge_chain: [{
102	          merged_id: mergedRecordId,
103	          surviving_id: survivingRecordId,
104	          merged_by: request.user.sub,
105	          merged_at: new Date().toISOString(),
106	        }],
107	        snapshot: recordB,
108	      };
109	
110	      // Record merge history
111	      await cleansingRepo.createMergeHistory({
112	        duplicateCandidateId: candidateId,
113	        survivingId: survivingRecordId,
114	        mergedId: mergedRecordId,
115	        provenance,
116	        performedBy: request.user.sub,
117	      });
118	
119	      // Soft-delete the merged offering (archive it)
120	      await offeringRepo.updateStatus(mergedRecordId, 'archived');
121	    }
122	
123	    // Update candidate status
124	    await cleansingRepo.updateCandidateStatus(candidateId, 'merged', request.user.sub);
125	
126	    request.auditContext = {
127	      resourceType: 'duplicate_candidate',
128	      resourceId: candidateId,
129	      afterState: { status: 'merged', survivingRecordId, mergedRecordId },
130	    };
131	
132	    return reply.status(200).send({
133	      candidateId,
134	      status: 'merged',
135	      survivingRecordId,
136	      mergedRecordId,
137	    });
138	  });
139	
140	  // POST /dedup/:candidateId/dismiss
141	  fastify.post('/:candidateId/dismiss', {
142	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
143	  }, async (request, reply) => {
144	    const { candidateId } = request.params as { candidateId: string };
145	
146	    const candidate = await cleansingRepo.findCandidateById(candidateId);
147	    if (!candidate) {
148	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
149	    }
150	
151	    if (candidate.status !== 'pending') {
152	      return reply.status(409).send({ error: 'CANDIDATE_ALREADY_RESOLVED', message: `Candidate is already ${candidate.status}`, currentStatus: candidate.status });
153	    }
154	
155	    await cleansingRepo.updateCandidateStatus(candidateId, 'dismissed', request.user.sub);
156	
157	    request.auditContext = {
158	      resourceType: 'duplicate_candidate',
159	      resourceId: candidateId,
160	      afterState: { status: 'dismissed' },
161	    };
162	
163	    return reply.status(200).send({ candidateId, status: 'dismissed' });
164	  });
165	
166	  // GET /data-quality/flags
167	  fastify.get('/data-quality/flags', {
168	    preHandler: [fastify.authenticate, fastify.authorize('data_quality', 'review')],
169	  }, async (request, reply) => {
170	    const query = request.query as { status?: string; recordType?: string; page?: string; limit?: string };
171	    const page = Math.max(1, parseInt(query.page || '1', 10));
172	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
173	
174	    const result = await cleansingRepo.listFlags({
175	      status: query.status || 'open',
176	      recordType: query.recordType,
177	      page,
178	      limit,
179	    });
180	
181	    return reply.status(200).send({
182	      data: result.data,
183	      meta: { page, limit, total: result.total, totalPages: Math.ceil(result.total / limit) },
184	    });
185	  });
186	
187	  // POST /data-quality/flags/:id/resolve
188	  fastify.post('/data-quality/flags/:id/resolve', {
189	    preHandler: [fastify.authenticate, fastify.authorize('data_quality', 'resolve')],
190	  }, async (request, reply) => {
191	    const { id } = request.params as { id: string };
192	    await cleansingRepo.resolveFlag(id, request.user.sub);
193	    return reply.status(200).send({ id, status: 'resolved' });
194	  });
195	}
