101	export class OfferingsComponent implements OnInit {
102	  private http = inject(HttpClient);
103	  private auth = inject(AuthService);
104	  private notifications = inject(NotificationService);
105	
106	  offerings = signal<Offering[]>([]);
107	  loading = signal(true);
108	  total = signal(0);
109	  page = signal(1);
110	  totalPages = signal(1);
111	  showCreateDialog = false;
112	  editingId = signal<string | null>(null);
113	  orgId = signal('');
114	
115	  canCreate = () => ['merchant', 'administrator'].includes(this.auth.role());
116	
117	  ngOnInit(): void {
118	    this.loadOfferings();
119	  }
120	
121	  async loadOfferings(): Promise<void> {
122	    this.loading.set(true);
123	    try {
124	      const res = await firstValueFrom(
125	        this.http.get<any>(`/api/v1/offerings?page=${this.page()}&limit=20`),
126	      );
127	      this.offerings.set(res.data);
128	      this.total.set(res.meta.total);
129	      this.totalPages.set(res.meta.totalPages);
130	    } catch {
131	      this.notifications.error('Failed to load offerings');
132	    } finally {
133	      this.loading.set(false);
134	    }
135	  }
136	
137	  formatPrice(cents: number): string {
138	    return '$' + (cents / 100).toFixed(2).replace(/\B(?=(\d{3})+(?!\d))/g, ',');
139	  }
140	
141	  formatDuration(minutes: number): string {
142	    if (minutes >= 60) {
143	      const h = Math.floor(minutes / 60);
144	      const m = minutes % 60;
145	      return m > 0 ? `${h}hr ${m}min` : `${h}hr`;
146	    }
147	    return `${minutes}min`;
148	  }
149	
150	  statusClass(status: string): string {
151	    switch (status) {
152	      case 'active': return 'bg-green-100 text-green-800';
153	      case 'draft': return 'bg-yellow-100 text-yellow-800';
154	      case 'archived': return 'bg-gray-100 text-gray-600';
155	      default: return 'bg-gray-100 text-gray-600';
156	    }
157	  }
158	
159	  prevPage(): void {
160	    if (this.page() > 1) { this.page.update(p => p - 1); this.loadOfferings(); }
161	  }
162	
163	  nextPage(): void {
164	    if (this.page() < this.totalPages()) { this.page.update(p => p + 1); this.loadOfferings(); }
165	  }
166	
167	  openCreate(): void {
168	    // Use orgId from first existing offering or the user's context
169	    const first = this.offerings()[0];
170	    if (first) this.orgId.set((first as any).orgId);
171	    this.showCreateDialog = true;
172	  }
173	
174	  editOffering(id: string): void {
175	    this.editingId.set(id);
176	    // Capture orgId from the offering being edited
177	    const offering = this.offerings().find(o => o.id === id);
178	    if (offering) this.orgId.set((offering as any).orgId);
179	  }
180	
181	  closeForm(): void {
182	    this.showCreateDialog = false;
183	    this.editingId.set(null);
184	  }
185	
186	  onSaved(): void {
187	    this.loadOfferings();
188	  }
189	}
