115	export class OfferingFormComponent implements OnInit {
116	  private http = inject(HttpClient);
117	  private notifications = inject(NotificationService);
118	
119	  orgId = input.required<string>();
120	  editId = input<string | null>(null);
121	  close = output();
122	  saved = output();
123	
124	  title = '';
125	  description = '';
126	  priceUsd = 0;
127	  durationMinutes = 0;
128	  visibility = 'public';
129	  submitting = signal(false);
130	  errorMsg = signal('');
131	  addons = signal<any[]>([]);
132	  currentStatus = signal('draft');
133	  accessUserIds = signal<string[]>([]);
134	  newAddonName = '';
135	  newAddonPrice = 0;
136	  newAddonUnit = '';
137	  newAccessUserId = '';
138	
139	  ngOnInit(): void {
140	    if (this.editId()) this.loadOffering();
141	  }
142	
143	  async loadOffering(): Promise<void> {
144	    const res = await firstValueFrom(this.http.get<any>(`/api/v1/offerings/${this.editId()}`));
145	    this.title = res.title;
146	    this.description = res.description || '';
147	    this.priceUsd = res.basePriceCents / 100;
148	    this.durationMinutes = res.durationMinutes;
149	    this.visibility = res.visibility;
150	    this.addons.set(res.addons || []);
151	    this.currentStatus.set(res.status || 'draft');
152	  }
153	
154	  async onSubmit(): Promise<void> {
155	    this.errorMsg.set('');
156	    this.submitting.set(true);
157	    try {
158	      const payload = {
159	        title: this.title, description: this.description,
160	        basePriceCents: Math.round(this.priceUsd * 100),
161	        durationMinutes: this.durationMinutes, visibility: this.visibility,
162	        orgId: this.orgId(),
163	      };
164	
165	      if (this.editId()) {
166	        await firstValueFrom(this.http.put(`/api/v1/offerings/${this.editId()}`, payload));
167	        this.notifications.success('Offering updated');
168	      } else {
169	        const res = await firstValueFrom(this.http.post<any>('/api/v1/offerings', payload));
170	        this.notifications.success('Offering created');
171	      }
172	      this.saved.emit();
173	      this.close.emit();
174	    } catch (err) {
175	      this.errorMsg.set(err instanceof HttpErrorResponse ? (err.error?.message || 'Save failed') : 'Save failed');
176	    } finally {
177	      this.submitting.set(false);
178	    }
179	  }
180	
181	  async addAddon(): Promise<void> {
182	    if (!this.editId() || !this.newAddonName) return;
183	    try {
184	      await firstValueFrom(this.http.post(`/api/v1/offerings/${this.editId()}/addons`, {
185	        name: this.newAddonName, priceCents: Math.round(this.newAddonPrice * 100), unitDescription: this.newAddonUnit || 'each',
186	      }));
187	      this.newAddonName = ''; this.newAddonPrice = 0; this.newAddonUnit = '';
188	      this.loadOffering();
189	    } catch { this.notifications.error('Failed to add add-on'); }
190	  }
191	
192	  async deleteAddon(addonId: string): Promise<void> {
193	    try {
194	      await firstValueFrom(this.http.delete(`/api/v1/offerings/${this.editId()}/addons/${addonId}`));
195	      this.addons.update(list => list.filter(a => a.id !== addonId));
196	    } catch { this.notifications.error('Failed to remove add-on'); }
197	  }
198	
199	  async changeStatus(status: string): Promise<void> {
200	    try {
201	      await firstValueFrom(this.http.patch(`/api/v1/offerings/${this.editId()}/status`, { status }));
202	      this.currentStatus.set(status);
203	      this.notifications.success(`Offering ${status === 'active' ? 'published' : 'archived'}`);
204	      this.saved.emit();
205	    } catch (err) {
206	      this.notifications.error(err instanceof HttpErrorResponse ? (err.error?.message || 'Status change failed') : 'Status change failed');
207	    }
208	  }
209	
210	  async grantAccess(): Promise<void> {
211	    if (!this.newAccessUserId.trim()) return;
212	    try {
213	      await firstValueFrom(this.http.post(`/api/v1/offerings/${this.editId()}/access`, {
214	        userIds: [this.newAccessUserId.trim()],
215	      }));
216	      this.accessUserIds.update(list => [...list, this.newAccessUserId.trim()]);
217	      this.newAccessUserId = '';
218	      this.notifications.success('Access granted');
219	    } catch { this.notifications.error('Failed to grant access'); }
220	  }
221	
222	  async revokeAccess(userId: string): Promise<void> {
223	    try {
224	      await firstValueFrom(this.http.delete(`/api/v1/offerings/${this.editId()}/access/${userId}`));
225	      this.accessUserIds.update(list => list.filter(id => id !== userId));
226	      this.notifications.success('Access revoked');
227	    } catch { this.notifications.error('Failed to revoke access'); }
228	  }
229	}
