163	export class DashboardComponent implements OnInit {
164	  private http = inject(HttpClient);
165	  private notifications = inject(NotificationService);
166	
167	  payload = signal<any>(null);
168	  loading = signal(true);
169	  exporting = signal(false);
170	  hasFilePicker = 'showSaveFilePicker' in (typeof window !== 'undefined' ? window : {});
171	  dateFrom = '2026-01-01';
172	  dateTo = '2026-12-31';
173	  eventType = '';
174	
175	  orgId = '';
176	  totalEvents = signal(0);
177	  conversionRate = signal('0.0');
178	  attendanceRate = signal('0.0');
179	  cancellationRate = signal('0.0');
180	  maxPopularity = signal(1);
181	
182	  ngOnInit(): void {
183	    this.loadDashboard();
184	  }
185	
186	  async loadDashboard(): Promise<void> {
187	    this.loading.set(true);
188	    try {
189	      let url = `/api/v1/analytics/dashboard?from=${this.dateFrom}&to=${this.dateTo}`;
190	      if (this.orgId) url += `&orgId=${this.orgId}`;
191	      if (this.eventType) url += `&eventType=${this.eventType}`;
192	
193	      const data = await firstValueFrom(this.http.get<any>(url));
194	      this.payload.set(data);
195	
196	      const pop = data.popularity?.data ?? [];
197	      this.totalEvents.set(pop.reduce((a: number, b: number) => a + b, 0));
198	      this.maxPopularity.set(Math.max(1, ...pop));
199	
200	      const funnel = data.conversionFunnel?.counts ?? [0, 0, 0];
201	      this.conversionRate.set(funnel[0] > 0 ? ((funnel[1] / funnel[0]) * 100).toFixed(1) : '0.0');
202	
203	      const att = data.attendanceRate?.rates ?? [0, 0];
204	      this.attendanceRate.set((att[0] * 100).toFixed(1));
205	
206	      const can = data.cancellationRate?.rates ?? [0, 0];
207	      this.cancellationRate.set((can[1] * 100).toFixed(1));
208	    } catch {
209	      this.notifications.error('Failed to load dashboard');
210	    } finally {
211	      this.loading.set(false);
212	    }
213	  }
214	
215	  async exportData(format: string): Promise<void> {
216	    this.exporting.set(true);
217	    try {
218	      const res = await firstValueFrom(
219	        this.http.post(`/api/v1/analytics/export`, {
220	          format,
221	          filters: { from: this.dateFrom, to: this.dateTo, orgId: this.orgId || undefined, eventType: this.eventType || undefined },
222	        }, { responseType: 'blob' }),
223	      );
224	
225	      const ext = format === 'xlsx' ? 'xlsx' : 'csv';
226	      const mimeType = format === 'xlsx'
227	        ? 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
228	        : 'text/csv';
229	      const suggestedName = `analytics-${new Date().toISOString().split('T')[0]}.${ext}`;
230	
231	      // File System Access API — save to user-selected local folder
232	      const handle = await (window as any).showSaveFilePicker({
233	        suggestedName,
234	        types: [{
235	          description: format === 'xlsx' ? 'Excel Spreadsheet' : 'CSV File',
236	          accept: { [mimeType]: [`.${ext}`] },
237	        }],
238	      });
239	      const writable = await handle.createWritable();
240	      await writable.write(res);
241	      await writable.close();
242	      this.notifications.success(`${format.toUpperCase()} saved to selected folder`);
243	    } catch (err: any) {
244	      if (err?.name === 'AbortError') {
245	        // User cancelled the file picker — not an error
246	      } else {
247	        this.notifications.error('Export failed. You may need to wait for the cooldown period.');
248	      }
249	    } finally {
250	      this.exporting.set(false);
251	    }
252	  }
253	
254	  barWidth(value: number, max: number): number {
255	    return Math.max(8, (value / max) * 120);
256	  }
257	}
