1	import { randomUUID } from 'node:crypto';
2	import { LOCKOUT, SESSION } from '@studioops/shared';
3	import { generateRefreshToken } from '../domain/refresh-token';
4	import type { PasswordHasherPort } from '../ports/password-hasher.port';
5	import type { UserRepositoryPort } from '../ports/user-repository.port';
6	import type { SessionRepositoryPort } from '../ports/session-repository.port';
7	import type { LockoutRepositoryPort } from '../ports/lockout-repository.port';
8	
9	export interface LoginInput {
10	  username: string;
11	  password: string;
12	}
13	
14	export interface LoginResult {
15	  accessTokenPayload: { sub: string; role: string; jti: string };
16	  refreshToken: string;
17	  expiresIn: number;
18	}
19	
20	export class AuthenticationError extends Error {
21	  public readonly statusCode = 401;
22	  constructor(message: string = 'Invalid credentials') {
23	    super(message);
24	    this.name = 'AuthenticationError';
25	  }
26	}
27	
28	export class LockoutError extends Error {
29	  public readonly statusCode = 429;
30	  public readonly retryAfter: number;
31	
32	  constructor(retryAfterSeconds: number) {
33	    super('Account temporarily locked');
34	    this.name = 'LockoutError';
35	    this.retryAfter = retryAfterSeconds;
36	  }
37	}
38	
39	export class LoginUseCase {
40	  constructor(
41	    private userRepo: UserRepositoryPort,
42	    private passwordHasher: PasswordHasherPort,
43	    private sessionRepo: SessionRepositoryPort,
44	    private lockoutRepo: LockoutRepositoryPort,
45	  ) {}
46	
47	  async execute(input: LoginInput): Promise<LoginResult> {
48	    const username = input.username.trim().toLowerCase();
49	
50	    const user = await this.userRepo.findByUsername(username);
51	    if (!user) {
52	      throw new AuthenticationError();
53	    }
54	
55	    // Check active lockout
56	    const lockout = await this.lockoutRepo.getActiveLockout(user.id);
57	    if (lockout && lockout.expiresAt && lockout.expiresAt > new Date()) {
58	      const retryAfter = Math.ceil((lockout.expiresAt.getTime() - Date.now()) / 1000);
59	      throw new LockoutError(retryAfter);
60	    }
61	
62	    // Verify password
63	    const isValid = await this.passwordHasher.verify(input.password, user.passwordHash);
64	    if (!isValid) {
65	      await this.lockoutRepo.recordFailedAttempt(user.id);
66	      const recentCount = await this.lockoutRepo.getRecentFailedAttemptCount(
67	        user.id,
68	        LOCKOUT.WINDOW_SECONDS,
69	      );
70	
71	      if (recentCount >= LOCKOUT.MAX_ATTEMPTS) {
72	        const expiresAt = new Date(Date.now() + LOCKOUT.DURATION_SECONDS * 1000);
73	        await this.lockoutRepo.createLockout(
74	          user.id,
75	          expiresAt,
76	          `${LOCKOUT.MAX_ATTEMPTS} failed login attempts`,
77	        );
78	      }
79	
80	      throw new AuthenticationError();
81	    }
82	
83	    // Clear failed attempts on success
84	    await this.lockoutRepo.clearFailedAttempts(user.id);
85	
86	    // Create session
87	    const jti = randomUUID();
88	    const now = new Date();
89	    const absoluteExpiresAt = new Date(now.getTime() + SESSION.ABSOLUTE_SESSION_LIFETIME_SECONDS * 1000);
90	
91	    const session = await this.sessionRepo.createSession({
92	      userId: user.id,
93	      tokenJti: jti,
94	      absoluteExpiresAt,
95	    });
96	
97	    // Create refresh token
98	    const refreshTokenPair = generateRefreshToken();
99	    const refreshExpiresAt = new Date(now.getTime() + SESSION.REFRESH_TOKEN_LIFETIME_SECONDS * 1000);
100	
101	    await this.sessionRepo.createRefreshToken({
102	      sessionId: session.id,
103	      tokenHash: refreshTokenPair.hash,
104	      expiresAt: refreshExpiresAt,
105	      absoluteExpiresAt,
106	    });
107	
108	    return {
109	      accessTokenPayload: { sub: user.id, role: user.role, jti },
110	      refreshToken: refreshTokenPair.plaintext,
111	      expiresIn: SESSION.ACCESS_TOKEN_LIFETIME_SECONDS,
112	    };
113	  }
114	}
