2	import { sessions, refreshTokens } from '@studioops/db/schema';
3	import type {
4	  SessionRepositoryPort,
5	  SessionRecord,
6	  RefreshTokenRecord,
7	  CreateSessionInput,
8	  CreateRefreshTokenInput,
9	} from '../../core/ports/session-repository.port';
10	import type { PostgresJsDatabase } from 'drizzle-orm/postgres-js';
11	type Database = PostgresJsDatabase<any>;
12	
13	export class DrizzleSessionRepository implements SessionRepositoryPort {
14	  constructor(private db: Database) {}
15	
16	  async createSession(input: CreateSessionInput): Promise<SessionRecord> {
17	    const [row] = await this.db
18	      .insert(sessions)
19	      .values({
20	        userId: input.userId,
21	        tokenJti: input.tokenJti,
22	        absoluteExpiresAt: input.absoluteExpiresAt,
23	      })
24	      .returning();
25	    return this.toSessionRecord(row);
26	  }
27	
28	  async createRefreshToken(input: CreateRefreshTokenInput): Promise<RefreshTokenRecord> {
29	    const [row] = await this.db
30	      .insert(refreshTokens)
31	      .values({
32	        sessionId: input.sessionId,
33	        tokenHash: input.tokenHash,
34	        expiresAt: input.expiresAt,
35	        absoluteExpiresAt: input.absoluteExpiresAt,
36	      })
37	      .returning();
38	    return this.toRefreshTokenRecord(row);
39	  }
40	
41	  async findRefreshTokenByHash(hash: string): Promise<RefreshTokenRecord | null> {
42	    const rows = await this.db
43	      .select()
44	      .from(refreshTokens)
45	      .where(eq(refreshTokens.tokenHash, hash))
46	      .limit(1);
47	    return rows[0] ? this.toRefreshTokenRecord(rows[0]) : null;
48	  }
49	
50	  async markRefreshTokenUsed(id: string): Promise<void> {
51	    await this.db.update(refreshTokens).set({ used: true }).where(eq(refreshTokens.id, id));
52	  }
53	
54	  async revokeAllRefreshTokensForUser(userId: string): Promise<number> {
55	    // Find all sessions for user, then mark all their refresh tokens as used
56	    const userSessions = await this.db
57	      .select({ id: sessions.id })
58	      .from(sessions)
59	      .where(eq(sessions.userId, userId));
60	
61	    if (userSessions.length === 0) return 0;
62	
63	    const sessionIds = userSessions.map((s) => s.id);
64	
65	    let count = 0;
66	    for (const sid of sessionIds) {
67	      const result = await this.db
68	        .update(refreshTokens)
69	        .set({ used: true })
70	        .where(and(eq(refreshTokens.sessionId, sid), eq(refreshTokens.used, false)));
71	      // Drizzle doesn't return affected count easily in all cases, so count sessions
72	      count++;
73	    }
74	
75	    // Also revoke all sessions
76	    await this.db
77	      .update(sessions)
78	      .set({ revoked: true })
79	      .where(eq(sessions.userId, userId));
80	
81	    return count;
82	  }
83	
84	  async findSessionById(id: string): Promise<SessionRecord | null> {
85	    const rows = await this.db.select().from(sessions).where(eq(sessions.id, id)).limit(1);
86	    return rows[0] ? this.toSessionRecord(rows[0]) : null;
87	  }
88	
89	  private toSessionRecord(row: typeof sessions.$inferSelect): SessionRecord {
90	    return {
91	      id: row.id,
92	      userId: row.userId,
93	      tokenJti: row.tokenJti,
94	      issuedAt: row.issuedAt,
95	      lastActivityAt: row.lastActivityAt,
96	      absoluteExpiresAt: row.absoluteExpiresAt,
97	      revoked: row.revoked,
98	      revokedBy: row.revokedBy,
99	    };
100	  }
101	
102	  private toRefreshTokenRecord(row: typeof refreshTokens.$inferSelect): RefreshTokenRecord {
103	    return {
104	      id: row.id,
105	      sessionId: row.sessionId,
106	      tokenHash: row.tokenHash,
107	      expiresAt: row.expiresAt,
108	      absoluteExpiresAt: row.absoluteExpiresAt,
109	      used: row.used,
110	      createdAt: row.createdAt,
111	    };
112	  }
113	}
