31	  const registerUseCase = new RegisterUseCase(userRepo, hasher);
32	  const loginUseCase = new LoginUseCase(userRepo, hasher, sessionRepo, lockoutRepo);
33	  const refreshUseCase = new RefreshUseCase(sessionRepo, async (userId: string) => {
