39	  fastify.post('/register', async (request, reply) => {
40	    const parseResult = registerSchema.safeParse(request.body);
41	    if (!parseResult.success) {
42	      return reply.status(400).send({
43	        error: 'VALIDATION_ERROR',
44	        message: 'Validation failed',
45	        details: parseResult.error.issues.map((i) => i.message),
46	      });
47	    }
48	
49	    try {
50	      const result = await registerUseCase.execute(parseResult.data);
51	      return reply.status(201).send(result);
52	    } catch (err) {
53	      if (err instanceof ValidationError) {
54	        return reply.status(400).send({
55	          error: 'VALIDATION_ERROR',
56	          message: err.message,
57	          details: err.details,
58	        });
59	      }
60	      if (err instanceof ConflictError) {
61	        return reply.status(409).send({
62	          error: 'CONFLICT',
63	          message: err.message,
64	        });
65	      }
66	      throw err;
67	    }
68	  });
69	
70	  // POST /auth/login
71	  fastify.post('/login', async (request, reply) => {
72	    const parseResult = loginSchema.safeParse(request.body);
73	    if (!parseResult.success) {
74	      return reply.status(400).send({
75	        error: 'VALIDATION_ERROR',
76	        message: 'Validation failed',
77	        details: parseResult.error.issues.map((i) => i.message),
78	      });
79	    }
80	
81	    try {
82	      const result = await loginUseCase.execute(parseResult.data);
83	      const accessToken = fastify.jwt.sign(result.accessTokenPayload);
84	
85	      return reply.status(200).send({
86	        accessToken,
87	        refreshToken: result.refreshToken,
88	        expiresIn: result.expiresIn,
89	      });
90	    } catch (err) {
91	      if (err instanceof LockoutError) {
92	        reply.header('Retry-After', String(err.retryAfter));
93	        return reply.status(429).send({
94	          error: 'ACCOUNT_LOCKED',
95	          message: err.message,
96	          retryAfter: err.retryAfter,
97	        });
98	      }
99	      if (err instanceof AuthenticationError) {
100	        return reply.status(401).send({
101	          error: 'INVALID_CREDENTIALS',
102	          message: err.message,
103	        });
104	      }
105	      throw err;
106	    }
107	  });
108	
109	  // POST /auth/refresh
110	  fastify.post('/refresh', async (request, reply) => {
111	    const parseResult = refreshSchema.safeParse(request.body);
112	    if (!parseResult.success) {
113	      return reply.status(400).send({
114	        error: 'VALIDATION_ERROR',
115	        message: 'Validation failed',
116	        details: parseResult.error.issues.map((i) => i.message),
117	      });
118	    }
119	
120	    try {
121	      const result = await refreshUseCase.execute(parseResult.data);
122	      const accessToken = fastify.jwt.sign(result.accessTokenPayload);
123	
124	      return reply.status(200).send({
125	        accessToken,
126	        refreshToken: result.refreshToken,
127	        expiresIn: result.expiresIn,
128	      });
129	    } catch (err) {
130	      if (err instanceof AuthenticationError) {
131	        return reply.status(401).send({
132	          error: 'INVALID_TOKEN',
133	          message: err.message,
134	        });
135	      }
136	      throw err;
137	    }
138	  });
139	
140	  // POST /auth/logout
141	  fastify.post('/logout', {
142	    preHandler: [fastify.authenticate],
143	  }, async (request, reply) => {
144	    const body = request.body as { refreshToken?: string } | undefined;
145	    const userId = request.user.sub;
146	
147	    if (body?.refreshToken) {
148	      const { hashRefreshToken } = await import('../../core/domain/refresh-token');
149	      const hash = hashRefreshToken(body.refreshToken);
150	      const token = await sessionRepo.findRefreshTokenByHash(hash);
151	      if (token) {
152	        await sessionRepo.markRefreshTokenUsed(token.id);
153	      }
154	    } else {
155	      await sessionRepo.revokeAllRefreshTokensForUser(userId);
156	    }
157	
158	    return reply.status(204).send();
159	  });
160	
161	  // GET /auth/session
162	  fastify.get('/session', {
163	    preHandler: [fastify.authenticate],
164	  }, async (request, reply) => {
165	    const user = await userRepo.findById(request.user.sub);
166	    if (!user) {
167	      return reply.status(401).send({
168	        error: 'UNAUTHORIZED',
169	        message: 'User not found',
170	      });
171	    }
172	
173	    return reply.status(200).send({
174	      id: user.id,
175	      username: user.username,
176	      role: user.role,
177	    });
178	  });
179	
180	  // DELETE /auth/sessions/:userId (Admin only)
181	  fastify.delete('/sessions/:userId', {
182	    preHandler: [fastify.authenticate],
183	  }, async (request, reply) => {
184	    const { userId } = request.params as { userId: string };
185	
186	    if (request.user.role !== 'administrator') {
187	      return reply.status(403).send({
188	        error: 'FORBIDDEN',
189	        message: 'Insufficient permissions',
190	      });
191	    }
192	
193	    const revokedCount = await sessionRepo.revokeAllRefreshTokensForUser(userId);
194	
195	    return reply.status(200).send({ revokedCount });
196	  });
197	}
