1	import { Injectable, signal, computed } from '@angular/core';
2	import { HttpClient } from '@angular/common/http';
3	import { Router } from '@angular/router';
4	import { firstValueFrom } from 'rxjs';
5	
6	export interface UserSession {
7	  id: string;
8	  username: string;
9	  role: string;
10	}
11	
12	interface LoginResponse {
13	  accessToken: string;
14	  refreshToken: string;
15	  expiresIn: number;
16	}
17	
18	interface RegisterResponse {
19	  id: string;
20	  username: string;
21	  createdAt: string;
22	}
23	
24	@Injectable({ providedIn: 'root' })
25	export class AuthService {
26	  private _user = signal<UserSession | null>(null);
27	  private _token = signal<string | null>(null);
28	  private _loading = signal(false);
29	
30	  readonly user = this._user.asReadonly();
31	  readonly token = this._token.asReadonly();
32	  readonly loading = this._loading.asReadonly();
33	  readonly isAuthenticated = computed(() => !!this._token());
34	  readonly role = computed(() => this._user()?.role ?? 'guest');
35	
36	  constructor(private http: HttpClient, private router: Router) {
37	    this.ready = new Promise<void>((resolve) => { this._resolveReady = resolve; });
38	    this.restoreSession();
39	  }
40	
41	  async register(username: string, password: string): Promise<RegisterResponse> {
42	    return firstValueFrom(
43	      this.http.post<RegisterResponse>('/api/v1/auth/register', { username, password }),
44	    );
45	  }
46	
47	  async login(username: string, password: string): Promise<void> {
48	    this._loading.set(true);
49	    try {
50	      const res = await firstValueFrom(
51	        this.http.post<LoginResponse>('/api/v1/auth/login', { username, password }),
52	      );
53	      this.setTokens(res.accessToken, res.refreshToken);
54	      await this.fetchSession();
55	      this.router.navigate([this.getDefaultRoute()]);
56	    } finally {
57	      this._loading.set(false);
58	    }
59	  }
60	
61	  async logout(): Promise<void> {
62	    const token = this._token();
63	    if (token) {
64	      try {
65	        await firstValueFrom(this.http.post('/api/v1/auth/logout', {}));
66	      } catch { /* ignore logout failures */ }
67	    }
68	    this.clearSession();
69	    this.router.navigate(['/login']);
70	  }
71	
72	  async refreshToken(): Promise<string | null> {
73	    const refreshToken = localStorage.getItem('refreshToken');
74	    if (!refreshToken) return null;
75	
76	    try {
77	      const res = await firstValueFrom(
78	        this.http.post<LoginResponse>('/api/v1/auth/refresh', { refreshToken }),
79	      );
80	      this.setTokens(res.accessToken, res.refreshToken);
81	      return res.accessToken;
82	    } catch {
83	      this.clearSession();
84	      return null;
85	    }
86	  }
87	
88	  getDefaultRoute(): string {
89	    switch (this._user()?.role) {
90	      case 'administrator': return '/admin';
91	      case 'operations': return '/dashboard';
92	      case 'merchant': return '/offerings';
93	      case 'client': return '/';
94	      default: return '/';
95	    }
96	  }
97	
98	  private async fetchSession(): Promise<void> {
99	    try {
100	      const session = await firstValueFrom(
101	        this.http.get<UserSession>('/api/v1/auth/session'),
102	      );
103	      this._user.set(session);
104	    } catch {
105	      this.clearSession();
106	    }
107	  }
108	
109	  private setTokens(accessToken: string, refreshToken: string): void {
110	    this._token.set(accessToken);
111	    localStorage.setItem('accessToken', accessToken);
112	    localStorage.setItem('refreshToken', refreshToken);
113	  }
114	
115	  private clearSession(): void {
116	    this._token.set(null);
117	    this._user.set(null);
118	    localStorage.removeItem('accessToken');
119	    localStorage.removeItem('refreshToken');
120	  }
121	
122	  /** Promise that resolves when the initial session check is complete */
123	  readonly ready: Promise<void>;
124	  private _resolveReady!: () => void;
125	
126	  private restoreSession(): void {
127	    const token = localStorage.getItem('accessToken');
128	    if (token) {
129	      this._token.set(token);
130	      this.fetchSession().finally(() => this._resolveReady());
131	    } else {
132	      this._resolveReady();
133	    }
134	  }
135	}
