1	import { eq, and, or, inArray, sql, desc, count } from 'drizzle-orm';
2	import { offerings, offeringAddons, offeringAccess } from '@studioops/db/schema';
3	import type {
4	  OfferingRepositoryPort,
5	  OfferingRecord,
6	  AddonRecord,
7	  OfferingWithAddons,
8	  ListOfferingsParams,
9	  PaginatedOfferings,
10	  CreateOfferingData,
11	  UpdateOfferingData,
12	} from '../../core/ports/offering-repository.port';
13	import type { PostgresJsDatabase } from 'drizzle-orm/postgres-js';
14	type Database = PostgresJsDatabase<any>;
15	
16	export class DrizzleOfferingRepository implements OfferingRepositoryPort {
17	  constructor(private db: Database) {}
18	
19	  async create(data: CreateOfferingData): Promise<OfferingRecord> {
20	    const [row] = await this.db.insert(offerings).values({
21	      orgId: data.orgId,
22	      merchantId: data.merchantId,
23	      title: data.title,
24	      description: data.description || null,
25	      basePriceCents: data.basePriceCents,
26	      durationMinutes: data.durationMinutes,
27	      visibility: data.visibility,
28	      status: 'draft',
29	    }).returning();
30	    return this.toRecord(row);
31	  }
32	
33	  async findById(id: string): Promise<OfferingRecord | null> {
34	    const rows = await this.db.select().from(offerings).where(eq(offerings.id, id)).limit(1);
35	    return rows[0] ? this.toRecord(rows[0]) : null;
36	  }
37	
38	  async findByIdWithAddons(id: string): Promise<OfferingWithAddons | null> {
39	    const offering = await this.findById(id);
40	    if (!offering) return null;
41	
42	    const addons = await this.db.select().from(offeringAddons)
43	      .where(eq(offeringAddons.offeringId, id));
44	
45	    return {
46	      ...offering,
47	      addons: addons.map(this.toAddonRecord),
48	    };
49	  }
50	
51	  async list(params: ListOfferingsParams): Promise<PaginatedOfferings> {
52	    const { page, limit, orgId, status, role, userId, orgScope } = params;
53	    const offset = (page - 1) * limit;
54	
55	    const conditions: any[] = [];
56	
57	    // Status filter
58	    if (status) {
59	      conditions.push(eq(offerings.status, status));
60	    }
61	
62	    // Org filter
63	    if (orgId) {
64	      conditions.push(eq(offerings.orgId, orgId));
65	    }
66	
67	    // Visibility filtering based on role
68	    switch (role) {
69	      case 'administrator':
70	        // Admin sees everything
71	        break;
72	      case 'operations':
73	        // Ops sees all visibilities but scoped to their orgs
74	        if (orgScope && orgScope.length > 0) {
75	          conditions.push(inArray(offerings.orgId, orgScope));
76	        } else if (orgScope !== undefined) {
77	          conditions.push(sql`false`); // empty scope = no access
78	        }
79	        break;
80	      case 'merchant':
81	        // Merchant sees: public + own items (any visibility)
82	        if (userId) {
83	          conditions.push(
84	            or(
85	              eq(offerings.visibility, 'public'),
86	              eq(offerings.merchantId, userId),
87	            )!,
88	          );
89	        }
90	        break;
91	      case 'client':
92	        // Client sees: public+active, OR restricted items they have explicit access to
93	        if (!status) {
94	          conditions.push(eq(offerings.status, 'active'));
95	        }
96	        if (userId) {
97	          // Subquery: offering IDs the client has been granted access to
98	          const grantedSubquery = sql`(SELECT offering_id FROM offering_access WHERE user_id = ${userId})`;
99	          conditions.push(
100	            or(
101	              eq(offerings.visibility, 'public'),
102	              and(eq(offerings.visibility, 'restricted'), sql`${offerings.id} IN ${grantedSubquery}`),
103	            )!,
104	          );
105	        } else {
106	          conditions.push(eq(offerings.visibility, 'public'));
107	        }
108	        break;
109	      case 'guest':
110	      default:
111	        // Guest: public + active only
112	        conditions.push(eq(offerings.visibility, 'public'));
113	        if (!status) {
114	          conditions.push(eq(offerings.status, 'active'));
115	        }
116	        break;
117	    }
118	
119	    const where = conditions.length > 0 ? and(...conditions) : undefined;
120	
121	    const [totalResult] = await this.db.select({ count: count() }).from(offerings).where(where);
122	    const total = totalResult?.count ?? 0;
123	
124	    const rows = await this.db.select().from(offerings)
125	      .where(where)
126	      .orderBy(desc(offerings.createdAt))
127	      .limit(limit)
128	      .offset(offset);
129	
130	    return {
131	      data: rows.map(this.toRecord),
132	      total,
133	    };
134	  }
135	
136	  async update(id: string, data: UpdateOfferingData): Promise<OfferingRecord> {
137	    const updateData: any = { updatedAt: new Date() };
138	    if (data.title !== undefined) updateData.title = data.title;
139	    if (data.description !== undefined) updateData.description = data.description;
140	    if (data.basePriceCents !== undefined) updateData.basePriceCents = data.basePriceCents;
141	    if (data.durationMinutes !== undefined) updateData.durationMinutes = data.durationMinutes;
142	    if (data.visibility !== undefined) updateData.visibility = data.visibility;
143	
144	    const [row] = await this.db.update(offerings)
145	      .set(updateData)
146	      .where(eq(offerings.id, id))
147	      .returning();
148	    return this.toRecord(row);
149	  }
150	
151	  async updateStatus(id: string, status: string): Promise<OfferingRecord> {
152	    const [row] = await this.db.update(offerings)
153	      .set({ status: status as any, updatedAt: new Date() })
154	      .where(eq(offerings.id, id))
155	      .returning();
156	    return this.toRecord(row);
157	  }
158	
159	  async createAddon(offeringId: string, data: { name: string; priceCents: number; unitDescription: string }): Promise<AddonRecord> {
160	    const [row] = await this.db.insert(offeringAddons).values({
161	      offeringId,
162	      name: data.name,
163	      priceCents: data.priceCents,
164	      unitDescription: data.unitDescription,
165	    }).returning();
166	    return this.toAddonRecord(row);
167	  }
168	
169	  async deleteAddon(addonId: string): Promise<void> {
170	    await this.db.delete(offeringAddons).where(eq(offeringAddons.id, addonId));
171	  }
172	
173	  async findAddonById(addonId: string): Promise<AddonRecord | null> {
174	    const rows = await this.db.select().from(offeringAddons)
175	      .where(eq(offeringAddons.id, addonId)).limit(1);
176	    return rows[0] ? this.toAddonRecord(rows[0]) : null;
177	  }
178	
179	  async grantAccess(offeringId: string, userIds: string[], grantedBy: string): Promise<number> {
180	    let granted = 0;
181	    for (const userId of userIds) {
182	      try {
183	        await this.db.insert(offeringAccess).values({
184	          offeringId,
185	          userId,
186	          grantedBy,
187	        }).onConflictDoNothing();
