190	        // Skip conflicts
191	      }
192	    }
193	    return granted;
194	  }
195	
196	  async revokeAccess(offeringId: string, userId: string): Promise<void> {
197	    await this.db.delete(offeringAccess).where(
198	      and(eq(offeringAccess.offeringId, offeringId), eq(offeringAccess.userId, userId)),
199	    );
200	  }
201	
202	  async hasAccess(offeringId: string, userId: string): Promise<boolean> {
203	    const rows = await this.db.select().from(offeringAccess)
204	      .where(and(eq(offeringAccess.offeringId, offeringId), eq(offeringAccess.userId, userId)))
205	      .limit(1);
206	    return rows.length > 0;
207	  }
208	
209	  private toRecord(row: typeof offerings.$inferSelect): OfferingRecord {
210	    return {
211	      id: row.id,
212	      orgId: row.orgId,
213	      merchantId: row.merchantId,
214	      title: row.title,
215	      description: row.description,
216	      basePriceCents: row.basePriceCents,
217	      durationMinutes: row.durationMinutes,
218	      status: row.status,
