7	
8	export class DrizzlePermissionRepository implements PermissionRepositoryPort {
9	  constructor(private db: Database) {}
10	
11	  async getRolePermissions(role: Role): Promise<Set<string>> {
12	    const rows = await this.db
13	      .select({
14	        resource: permissions.resource,
15	        action: permissions.action,
16	      })
17	      .from(rolePermissions)
18	      .innerJoin(permissions, eq(rolePermissions.permissionId, permissions.id))
19	      .where(eq(rolePermissions.role, role));
20	
21	    return new Set(rows.map((r) => `${r.resource}:${r.action}`));
22	  }
