1	import { describe, it, expect, vi, beforeEach } from 'vitest';
2	import { RefreshUseCase } from '../../src/core/use-cases/refresh';
3	import { AuthenticationError } from '../../src/core/use-cases/login';
4	import type { SessionRepositoryPort, RefreshTokenRecord, SessionRecord } from '../../src/core/ports/session-repository.port';
5	
6	function makeRefreshToken(overrides: Partial<RefreshTokenRecord> = {}): RefreshTokenRecord {
7	  return {
8	    id: 'rt-1',
9	    sessionId: 'sess-1',
10	    tokenHash: 'hash',
11	    expiresAt: new Date(Date.now() + 3600_000),
12	    absoluteExpiresAt: new Date(Date.now() + 86400_000),
13	    used: false,
14	    createdAt: new Date(),
15	    ...overrides,
16	  };
17	}
18	
19	function makeSession(overrides: Partial<SessionRecord> = {}): SessionRecord {
20	  return {
21	    id: 'sess-1',
22	    userId: 'user-1',
23	    tokenJti: 'jti-1',
24	    issuedAt: new Date(),
25	    lastActivityAt: new Date(),
26	    absoluteExpiresAt: new Date(Date.now() + 86400_000),
27	    revoked: false,
28	    revokedBy: null,
29	    ...overrides,
30	  };
31	}
32	
33	describe('RefreshUseCase', () => {
34	  let sessionRepo: SessionRepositoryPort;
35	  let getUserRole: ReturnType<typeof vi.fn>;
36	  let useCase: RefreshUseCase;
37	
38	  beforeEach(() => {
39	    sessionRepo = {
40	      createSession: vi.fn(),
41	      createRefreshToken: vi.fn().mockResolvedValue({ id: 'rt-2' }),
42	      findRefreshTokenByHash: vi.fn().mockResolvedValue(makeRefreshToken()),
43	      markRefreshTokenUsed: vi.fn(),
44	      revokeAllRefreshTokensForUser: vi.fn(),
45	      findSessionById: vi.fn().mockResolvedValue(makeSession()),
46	    };
47	    getUserRole = vi.fn().mockResolvedValue('client');
48	    useCase = new RefreshUseCase(sessionRepo, getUserRole);
49	  });
50	
51	  it('issues new token pair and revokes old', async () => {
52	    const result = await useCase.execute({ refreshToken: 'old-token' });
53	
54	    expect(result.accessTokenPayload.sub).toBe('user-1');
55	    expect(result.refreshToken).toBeTruthy();
56	    expect(sessionRepo.markRefreshTokenUsed).toHaveBeenCalledWith('rt-1');
57	    expect(sessionRepo.createRefreshToken).toHaveBeenCalled();
58	  });
59	
60	  it('rejects when token not found', async () => {
61	    vi.mocked(sessionRepo.findRefreshTokenByHash).mockResolvedValue(null);
62	
63	    await expect(useCase.execute({ refreshToken: 'invalid' })).rejects.toThrow(AuthenticationError);
64	  });
65	
66	  it('rejects and revokes all when token already used (replay attack)', async () => {
67	    vi.mocked(sessionRepo.findRefreshTokenByHash).mockResolvedValue(makeRefreshToken({ used: true }));
68	
69	    await expect(useCase.execute({ refreshToken: 'reused' })).rejects.toThrow(AuthenticationError);
70	    expect(sessionRepo.revokeAllRefreshTokensForUser).toHaveBeenCalledWith('user-1');
71	  });
72	
73	  it('rejects expired refresh token', async () => {
74	    vi.mocked(sessionRepo.findRefreshTokenByHash).mockResolvedValue(
75	      makeRefreshToken({ expiresAt: new Date(Date.now() - 1000) }),
76	    );
77	
78	    await expect(useCase.execute({ refreshToken: 'expired' })).rejects.toThrow(AuthenticationError);
79	  });
80	
81	  it('rejects when absolute session expired', async () => {
82	    vi.mocked(sessionRepo.findRefreshTokenByHash).mockResolvedValue(
83	      makeRefreshToken({ absoluteExpiresAt: new Date(Date.now() - 1000) }),
84	    );
85	
86	    await expect(useCase.execute({ refreshToken: 'abs-expired' })).rejects.toThrow(AuthenticationError);
87	  });
88	
89	  it('slides absoluteExpiresAt forward on refresh (8hr from now)', async () => {
90	    const originalAbsExpiry = new Date(Date.now() + 86400_000);
91	    vi.mocked(sessionRepo.findRefreshTokenByHash).mockResolvedValue(
92	      makeRefreshToken({ absoluteExpiresAt: originalAbsExpiry }),
93	    );
94	
95	    const beforeRefresh = Date.now();
96	    await useCase.execute({ refreshToken: 'token' });
97	
98	    expect(sessionRepo.createRefreshToken).toHaveBeenCalledWith(
99	      expect.objectContaining({
100	        // absoluteExpiresAt should be ~8hr from now, NOT the original value
101	        absoluteExpiresAt: expect.any(Date),
102	      }),
103	    );
104	  });
105	
106	  it('rejects when session is revoked', async () => {
107	    vi.mocked(sessionRepo.findSessionById).mockResolvedValue(makeSession({ revoked: true }));
108	
109	    await expect(useCase.execute({ refreshToken: 'token' })).rejects.toThrow(AuthenticationError);
110	  });
111	});
