15	export default async function portfolioRoutes(fastify: FastifyInstance) {
16	  const portfolioRepo = new DrizzlePortfolioRepository(fastify.db);
17	  const cleansingRepo = new DrizzleCleansingRepository(fastify.db);
18	  const storageRoot = process.env.STORAGE_ROOT || './data/media';
19	
20	  // POST /portfolio/upload (with rules-engine quota enforcement)
21	  fastify.post('/upload', {
22	    preHandler: [fastify.authenticate, fastify.authorize('portfolio', 'upload'), fastify.enforceQuota('daily_upload_limit')],
23	  }, async (request, reply) => {
24	    const data = await request.file();
25	    if (!data) {
26	      return reply.status(400).send({ error: 'VALIDATION_ERROR', message: 'No file uploaded' });
27	    }
28	
29	    const mimeType = data.mimetype;
30	    const fileBuffer = await data.toBuffer();
31	    const fileSizeBytes = fileBuffer.length;
32	
33	    // Validate file
34	    const validation = validateFile(mimeType, fileSizeBytes, MAX_FILE_SIZE);
35	    if (!validation.valid) {
36	      return reply.status(422).send({
37	        error: validation.errorCode,
38	        message: validation.error,
39	      });
40	    }
41	
42	    // Quota is enforced by rules-engine preHandler (daily_upload_limit rule)
43	
44	    // Get org from authContext
45	    const orgId = request.authContext?.orgScope?.[0];
46	    if (!orgId) {
47	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'No organization assigned' });
48	    }
49	
50	    // Write original file to disk
51	    const fileId = randomUUID();
52	    const ext = mimeType.split('/')[1] === 'quicktime' ? 'mov' : mimeType.split('/')[1];
53	    const relativePath = join(orgId, 'originals', `${fileId}.${ext}`);
54	    const absolutePath = join(storageRoot, relativePath);
55	
56	    await mkdir(join(storageRoot, orgId, 'originals'), { recursive: true });
57	    await writeFile(absolutePath, fileBuffer);
58	
59	    // Parse title from fields or filename
60	    const fields = data.fields as any;
61	    const title = fields?.title?.value || data.filename || 'Untitled';
62	    const description = fields?.description?.value || null;
63	    const categoryId = fields?.categoryId?.value || null;
64	
65	    // Create DB record with status=pending
66	    const item = await portfolioRepo.createItem({
67	      merchantId: request.user.sub,
68	      originalOrgId: orgId,
69	      categoryId,
70	      title,
71	      description,
72	      mediaType: validation.mediaType!,
73	      originalPath: relativePath,
74	      mimeType,
75	      fileSizeBytes,
76	    });
77	
78	    // Async processing (fire-and-forget for photos, synchronous for now)
79	    if (validation.mediaType === 'photo') {
80	      // Process image in background
81	      const outputDir = join(storageRoot, orgId);
82	      processImage(absolutePath, outputDir, fileId)
83	        .then(async (result) => {
84	          await portfolioRepo.updateProcessingResult(item.id, {
85	            status: 'ready',
