87	            previewPath: join(orgId, 'previews', `${fileId}.jpg`),
88	            width: result.width,
89	            height: result.height,
90	          });
91	        })
92	        .catch(async (err) => {
93	          request.log.error({ err, itemId: item.id }, 'Media processing failed');
94	          await portfolioRepo.updateProcessingResult(item.id, {
95	            status: 'failed',
96	            errorDetail: (err as Error).message,
97	          });
98	        });
99	    } else if (validation.mediaType === 'video') {
100	      // Process video: transcode to 1080p H.264, extract poster frame
101	      const outputDir = join(storageRoot, orgId);
102	      processVideo(absolutePath, outputDir, fileId)
103	        .then(async (result) => {
104	          await portfolioRepo.updateProcessingResult(item.id, {
105	            status: 'ready',
106	            processedPath: join(orgId, 'processed', `${fileId}.mp4`),
107	            previewPath: join(orgId, 'previews', `${fileId}.jpg`),
108	            width: result.width,
109	            height: result.height,
110	            durationSeconds: result.durationSeconds,
111	          });
112	        })
113	        .catch(async (err) => {
114	          request.log.error({ err, itemId: item.id }, 'Video processing failed');
115	          await portfolioRepo.updateProcessingResult(item.id, {
116	            status: 'failed',
117	            errorDetail: (err as Error).message,
118	          });
119	        });
120	    }
121	
122	    request.auditContext = { resourceType: 'portfolio', resourceId: item.id, afterState: item };
123	
124	    // Auto-cleansing on upload metadata (fire-and-forget)
125	    (async () => {
