5	export default async function dedupRoutes(fastify: FastifyInstance) {
6	  const cleansingRepo = new DrizzleCleansingRepository(fastify.db);
7	  const offeringRepo = new DrizzleOfferingRepository(fastify.db);
8	
9	  // Helper: check if a candidate's records are within the user's org scope
10	  async function isCandidateInOrgScope(candidate: { recordType: string; recordAId: string }, orgScope: string[]): Promise<boolean> {
11	    if (candidate.recordType === 'offering') {
12	      const record = await offeringRepo.findById(candidate.recordAId);
13	      if (!record) return false;
14	      return orgScope.includes(record.orgId);
15	    }
16	    return true; // non-offering types pass through
17	  }
18	
19	  // GET /dedup/queue
20	  fastify.get('/queue', {
21	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
22	  }, async (request, reply) => {
23	    const query = request.query as { status?: string; recordType?: string; page?: string; limit?: string };
24	    const page = Math.max(1, parseInt(query.page || '1', 10));
25	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
26	
27	    const result = await cleansingRepo.listCandidates({
28	      status: query.status || 'pending',
29	      recordType: query.recordType,
30	      page,
31	      limit,
32	    });
33	
34	    // Filter by org scope for non-admin users
35	    let data = result.data;
36	    if (request.user.role !== 'administrator') {
37	      const orgScope = request.authContext?.orgScope ?? [];
38	      const filtered = [];
39	      for (const candidate of data) {
40	        if (await isCandidateInOrgScope(candidate, orgScope)) {
41	          filtered.push(candidate);
42	        }
43	      }
44	      data = filtered;
45	    }
46	
47	    return reply.status(200).send({
48	      data,
49	      meta: { page, limit, total: data.length, totalPages: Math.ceil(result.total / limit) },
50	    });
51	  });
52	
53	  // GET /dedup/:candidateId
54	  fastify.get('/:candidateId', {
55	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
56	  }, async (request, reply) => {
57	    const { candidateId } = request.params as { candidateId: string };
58	    const candidate = await cleansingRepo.findCandidateById(candidateId);
59	    if (!candidate) {
60	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
61	    }
62	
63	    // Load both records for side-by-side comparison
64	    let recordA = null;
65	    let recordB = null;
66	    if (candidate.recordType === 'offering') {
67	      recordA = await offeringRepo.findByIdWithAddons(candidate.recordAId);
68	      recordB = await offeringRepo.findByIdWithAddons(candidate.recordBId);
69	
70	      // Org-scope check for non-admin users
71	      if (request.user.role !== 'administrator' && recordA) {
72	        const orgScope = request.authContext?.orgScope ?? [];
73	        if (!orgScope.includes(recordA.orgId)) {
74	          return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
75	        }
76	      }
77	    }
78	
79	    return reply.status(200).send({ candidate, recordA, recordB });
80	  });
81	
82	  // POST /dedup/:candidateId/merge
83	  fastify.post('/:candidateId/merge', {
84	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'merge')],
85	  }, async (request, reply) => {
86	    const { candidateId } = request.params as { candidateId: string };
87	    const { survivingRecordId, mergedRecordId } = request.body as { survivingRecordId: string; mergedRecordId: string };
88	
89	    if (!survivingRecordId || !mergedRecordId) {
90	      return reply.status(400).send({ error: 'VALIDATION_ERROR', message: 'survivingRecordId and mergedRecordId are required' });
91	    }
92	
93	    if (survivingRecordId === mergedRecordId) {
94	      return reply.status(422).send({ error: 'SELF_MERGE_NOT_ALLOWED', message: 'Cannot merge a record with itself' });
95	    }
96	
97	    const candidate = await cleansingRepo.findCandidateById(candidateId);
98	    if (!candidate) {
99	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
