142	      await cleansingRepo.createMergeHistory({
143	        duplicateCandidateId: candidateId,
144	        survivingId: survivingRecordId,
145	        mergedId: mergedRecordId,
146	        provenance,
147	        performedBy: request.user.sub,
148	      });
149	
150	      // Soft-delete the merged offering (archive it)
151	      await offeringRepo.updateStatus(mergedRecordId, 'archived');
152	    }
153	
154	    // Update candidate status
155	    await cleansingRepo.updateCandidateStatus(candidateId, 'merged', request.user.sub);
156	
157	    request.auditContext = {
158	      resourceType: 'duplicate_candidate',
159	      resourceId: candidateId,
160	      afterState: { status: 'merged', survivingRecordId, mergedRecordId },
161	    };
162	
163	    return reply.status(200).send({
164	      candidateId,
165	      status: 'merged',
166	      survivingRecordId,
167	      mergedRecordId,
168	    });
169	  });
170	
171	  // POST /dedup/:candidateId/dismiss
172	  fastify.post('/:candidateId/dismiss', {
173	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
174	  }, async (request, reply) => {
175	    const { candidateId } = request.params as { candidateId: string };
176	
177	    const candidate = await cleansingRepo.findCandidateById(candidateId);
178	    if (!candidate) {
179	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
180	    }
181	
182	    // Org-scope check for non-admin users
183	    if (request.user.role !== 'administrator') {
184	      const orgScope = request.authContext?.orgScope ?? [];
185	      if (!(await isCandidateInOrgScope(candidate, orgScope))) {
186	        return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
187	      }
188	    }
189	
190	    if (candidate.status !== 'pending') {
191	      return reply.status(409).send({ error: 'CANDIDATE_ALREADY_RESOLVED', message: `Candidate is already ${candidate.status}`, currentStatus: candidate.status });
192	    }
193	
194	    await cleansingRepo.updateCandidateStatus(candidateId, 'dismissed', request.user.sub);
195	
196	    request.auditContext = {
197	      resourceType: 'duplicate_candidate',
198	      resourceId: candidateId,
199	      afterState: { status: 'dismissed' },
200	    };
201	
202	    return reply.status(200).send({ candidateId, status: 'dismissed' });
203	  });
204	
205	  // Helper: check if a data-quality flag's record is within org scope
206	  async function isFlagInOrgScope(flag: { recordType: string; recordId: string }, orgScope: string[]): Promise<boolean> {
207	    if (flag.recordType === 'offering') {
208	      const record = await offeringRepo.findById(flag.recordId);
209	      if (!record) return false;
210	      return orgScope.includes(record.orgId);
211	    }
212	    return true;
213	  }
214	
215	  // GET /data-quality/flags
216	  fastify.get('/data-quality/flags', {
217	    preHandler: [fastify.authenticate, fastify.authorize('data_quality', 'review')],
218	  }, async (request, reply) => {
219	    const query = request.query as { status?: string; recordType?: string; page?: string; limit?: string };
220	    const page = Math.max(1, parseInt(query.page || '1', 10));
221	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
222	
223	    const result = await cleansingRepo.listFlags({
224	      status: query.status || 'open',
225	      recordType: query.recordType,
226	      page,
227	      limit,
228	    });
229	
230	    // Filter by org scope for non-admin users
231	    let data = result.data;
232	    if (request.user.role !== 'administrator') {
233	      const orgScope = request.authContext?.orgScope ?? [];
234	      const filtered = [];
235	      for (const flag of data) {
236	        if (await isFlagInOrgScope(flag, orgScope)) {
237	          filtered.push(flag);
238	        }
239	      }
240	      data = filtered;
241	    }
242	
243	    return reply.status(200).send({
244	      data,
245	      meta: { page, limit, total: data.length, totalPages: Math.ceil(result.total / limit) },
246	    });
247	  });
248	
249	  // POST /data-quality/flags/:id/resolve
250	  fastify.post('/data-quality/flags/:id/resolve', {
251	    preHandler: [fastify.authenticate, fastify.authorize('data_quality', 'resolve')],
252	  }, async (request, reply) => {
253	    const { id } = request.params as { id: string };
254	
255	    // Org-scope check for non-admin users
256	    if (request.user.role !== 'administrator') {
257	      const flag = await cleansingRepo.findFlagById(id);
258	      if (flag) {
259	        const orgScope = request.authContext?.orgScope ?? [];
260	        if (!(await isFlagInOrgScope(flag, orgScope))) {
261	          return reply.status(404).send({ error: 'FLAG_NOT_FOUND', message: 'Flag not found' });
262	        }
263	      }
264	    }
265	
266	    await cleansingRepo.resolveFlag(id, request.user.sub);
267	    return reply.status(200).send({ id, status: 'resolved' });
268	  });
269	}
