1	import { describe, it, expect, afterAll, beforeAll } from 'vitest';
2	import { sql } from 'drizzle-orm';
3	import { createTestApp } from '../helpers/build-test-app';
4	import type { FastifyInstance } from 'fastify';
5	
6	const VALID_PASSWORD = 'ValidPass123!@';
7	
8	describe('Dedup & Data Quality Routes', () => {
9	  let app: FastifyInstance;
10	  let opsToken: string;
11	  let merchantToken: string;
12	  let orgId: string;
13	  let offeringAId: string;
14	  let offeringBId: string;
15	  let candidateId: string;
16	
17	  beforeAll(async () => {
18	    app = await createTestApp();
19	
20	    const orgs = await app.db.execute(sql`SELECT id FROM organizations LIMIT 1`);
21	    orgId = (orgs[0] as any).id;
22	
23	    // Create ops user
24	    const opsName = `ops_dedup_${Date.now()}`;
25	    await app.inject({ method: 'POST', url: '/api/v1/auth/register', payload: { username: opsName, password: VALID_PASSWORD } });
26	    await app.db.execute(sql`UPDATE users SET role = 'operations' WHERE username = ${opsName}`);
27	    const opsUser = await app.db.execute(sql`SELECT id FROM users WHERE username = ${opsName}`);
28	    await app.db.execute(sql`INSERT INTO organization_members (org_id, user_id, role_in_org) VALUES (${orgId}, ${(opsUser[0] as any).id}, 'member')`);
29	    const opsLogin = await app.inject({ method: 'POST', url: '/api/v1/auth/login', payload: { username: opsName, password: VALID_PASSWORD } });
30	    opsToken = opsLogin.json().accessToken;
31	
32	    // Create merchant
33	    const mName = `m_dedup_${Date.now()}`;
34	    await app.inject({ method: 'POST', url: '/api/v1/auth/register', payload: { username: mName, password: VALID_PASSWORD } });
35	    await app.db.execute(sql`UPDATE users SET role = 'merchant' WHERE username = ${mName}`);
36	    const mUser = await app.db.execute(sql`SELECT id FROM users WHERE username = ${mName}`);
37	    await app.db.execute(sql`INSERT INTO organization_members (org_id, user_id, role_in_org) VALUES (${orgId}, ${(mUser[0] as any).id}, 'member')`);
38	    const mLogin = await app.inject({ method: 'POST', url: '/api/v1/auth/login', payload: { username: mName, password: VALID_PASSWORD } });
39	    merchantToken = mLogin.json().accessToken;
40	
41	    // Create two similar offerings
42	    const resA = await app.inject({
43	      method: 'POST', url: '/api/v1/offerings',
44	      headers: { authorization: `Bearer ${merchantToken}` },
45	      payload: { title: 'Wedding Essentials Package', basePriceCents: 250000, durationMinutes: 360, orgId },
46	    });
47	    offeringAId = resA.json().id;
48	
49	    const resB = await app.inject({
50	      method: 'POST', url: '/api/v1/offerings',
51	      headers: { authorization: `Bearer ${merchantToken}` },
52	      payload: { title: 'Wedding Essential Package', basePriceCents: 250000, durationMinutes: 360, orgId },
53	    });
54	    offeringBId = resB.json().id;
55	
56	    // Manually create a dedup candidate (in production, the dedup pass would do this)
57	    await app.db.execute(sql`INSERT INTO duplicate_candidates (record_type, record_a_id, record_b_id, similarity_score, feature_scores, status) VALUES ('offering', ${offeringAId}, ${offeringBId}, '0.9500', '{"title":0.95,"price":1.0,"duration":1.0,"tags":1.0}'::jsonb, 'pending')`);
58	
59	    const candidates = await app.db.execute(sql`SELECT id FROM duplicate_candidates WHERE record_a_id = ${offeringAId} LIMIT 1`);
60	    candidateId = (candidates[0] as any).id;
61	  });
62	
63	  afterAll(async () => {
64	    if (app) await app.close();
65	  });
66	
67	  describe('GET /api/v1/dedup/queue', () => {
68	    it('returns pending candidates for Ops user', async () => {
69	      const res = await app.inject({
70	        method: 'GET',
71	        url: '/api/v1/dedup/queue',
72	        headers: { authorization: `Bearer ${opsToken}` },
73	      });
74	      expect(res.statusCode).toBe(200);
75	      expect(res.json().data.length).toBeGreaterThan(0);
76	    });
77	
78	    it('returns 403 for Merchant', async () => {
79	      const res = await app.inject({
80	        method: 'GET',
81	        url: '/api/v1/dedup/queue',
82	        headers: { authorization: `Bearer ${merchantToken}` },
83	      });
84	      expect(res.statusCode).toBe(403);
85	    });
86	  });
87	
88	  describe('GET /api/v1/dedup/:candidateId', () => {
89	    it('returns candidate with side-by-side records', async () => {
90	      const res = await app.inject({
91	        method: 'GET',
92	        url: `/api/v1/dedup/${candidateId}`,
93	        headers: { authorization: `Bearer ${opsToken}` },
94	      });
95	      expect(res.statusCode).toBe(200);
96	      const body = res.json();
97	      expect(body.candidate).toBeDefined();
98	      expect(body.recordA).toBeDefined();
99	      expect(body.recordB).toBeDefined();
100	    });
101	  });
102	
103	  describe('Merge workflow', () => {
104	    it('POST /dedup/:candidateId/merge merges records', async () => {
105	      const res = await app.inject({
106	        method: 'POST',
107	        url: `/api/v1/dedup/${candidateId}/merge`,
108	        headers: { authorization: `Bearer ${opsToken}` },
