127	      const selfMergeId = crypto.randomUUID();
128	      await app.db.execute(sql`INSERT INTO duplicate_candidates (id, record_type, record_a_id, record_b_id, similarity_score, feature_scores, status) VALUES (${selfMergeId}, 'offering', ${offeringAId}, ${offeringAId}, '1.0000', '{"title":1.0}'::jsonb, 'pending')`);
129	
130	      const res = await app.inject({
131	        method: 'POST',
132	        url: `/api/v1/dedup/${selfMergeId}/merge`,
133	        headers: { authorization: `Bearer ${opsToken}` },
134	        payload: { survivingRecordId: offeringAId, mergedRecordId: offeringAId },
135	      });
136	      expect(res.statusCode).toBe(422);
137	      expect(res.json().error).toBe('SELF_MERGE_NOT_ALLOWED');
138	    });
139	
140	    it('merge creates provenance in merge_history', async () => {
141	      const history = await app.db.execute(
142	        sql`SELECT * FROM merge_history WHERE duplicate_candidate_id = ${candidateId}`,
143	      );
144	      expect(history.length).toBe(1);
145	      const prov = (history[0] as any).provenance;
146	      expect(prov.merge_chain).toBeInstanceOf(Array);
147	      expect(prov.merge_chain[0].surviving_id).toBe(offeringAId);
148	      expect(prov.merge_chain[0].merged_id).toBe(offeringBId);
149	    });
150	  });
151	
152	  describe('Org-scope enforcement', () => {
153	    it('ops user from different org cannot view candidate detail', async () => {
154	      // Create a second org and an ops user assigned only to it
155	      await app.db.execute(sql`INSERT INTO organizations (id, name, slug) VALUES ('00000000-0000-4000-a000-000000000077', 'Other Org', 'other-org') ON CONFLICT DO NOTHING`);
156	      const otherOps = `ops_other_${Date.now()}`;
157	      await app.inject({ method: 'POST', url: '/api/v1/auth/register', payload: { username: otherOps, password: VALID_PASSWORD } });
158	      await app.db.execute(sql`UPDATE users SET role = 'operations' WHERE username = ${otherOps}`);
159	      const otherOpsUser = await app.db.execute(sql`SELECT id FROM users WHERE username = ${otherOps}`);
160	      await app.db.execute(sql`INSERT INTO organization_members (org_id, user_id, role_in_org) VALUES ('00000000-0000-4000-a000-000000000077', ${(otherOpsUser[0] as any).id}, 'member')`);
161	      const otherLogin = await app.inject({ method: 'POST', url: '/api/v1/auth/login', payload: { username: otherOps, password: VALID_PASSWORD } });
162	      const otherToken = otherLogin.json().accessToken;
163	
