1	import { FastifyInstance } from 'fastify';
2	import { DrizzleCleansingRepository } from '../../infrastructure/persistence/cleansing-repository';
3	import { DrizzleOfferingRepository } from '../../infrastructure/persistence/offering-repository';
4	import { DrizzlePortfolioRepository } from '../../infrastructure/persistence/portfolio-repository';
5	
6	export default async function dedupRoutes(fastify: FastifyInstance) {
7	  const cleansingRepo = new DrizzleCleansingRepository(fastify.db);
8	  const offeringRepo = new DrizzleOfferingRepository(fastify.db);
9	  const portfolioRepo = new DrizzlePortfolioRepository(fastify.db);
10	
11	  // Helper: resolve the orgId for a record by type
12	  async function getRecordOrgId(recordType: string, recordId: string): Promise<string | null> {
13	    if (recordType === 'offering') {
14	      const record = await offeringRepo.findById(recordId);
15	      return record?.orgId ?? null;
16	    }
17	    if (recordType === 'portfolio_item') {
18	      const record = await portfolioRepo.findById(recordId);
19	      return record?.originalOrgId ?? null;
20	    }
21	    return null;
22	  }
23	
24	  // Helper: check if a candidate's records are within the user's org scope
25	  async function isCandidateInOrgScope(candidate: { recordType: string; recordAId: string }, orgScope: string[]): Promise<boolean> {
26	    const orgId = await getRecordOrgId(candidate.recordType, candidate.recordAId);
27	    if (!orgId) return false;
28	    return orgScope.includes(orgId);
29	  }
30	
31	  // GET /dedup/queue
32	  fastify.get('/queue', {
33	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
34	  }, async (request, reply) => {
35	    const query = request.query as { status?: string; recordType?: string; page?: string; limit?: string };
36	    const page = Math.max(1, parseInt(query.page || '1', 10));
37	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
38	
39	    const result = await cleansingRepo.listCandidates({
40	      status: query.status || 'pending',
41	      recordType: query.recordType,
42	      page,
43	      limit,
44	    });
45	
46	    // Filter by org scope for non-admin users
47	    let data = result.data;
48	    if (request.user.role !== 'administrator') {
49	      const orgScope = request.authContext?.orgScope ?? [];
50	      const filtered = [];
51	      for (const candidate of data) {
52	        if (await isCandidateInOrgScope(candidate, orgScope)) {
53	          filtered.push(candidate);
54	        }
55	      }
56	      data = filtered;
57	    }
58	
59	    return reply.status(200).send({
60	      data,
61	      meta: { page, limit, total: data.length, totalPages: Math.ceil(result.total / limit) },
62	    });
63	  });
64	
65	  // GET /dedup/:candidateId
66	  fastify.get('/:candidateId', {
67	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
68	  }, async (request, reply) => {
69	    const { candidateId } = request.params as { candidateId: string };
70	    const candidate = await cleansingRepo.findCandidateById(candidateId);
71	    if (!candidate) {
72	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
73	    }
74	
75	    // Org-scope check for non-admin users (all record types)
76	    if (request.user.role !== 'administrator') {
77	      const orgScope = request.authContext?.orgScope ?? [];
78	      if (!(await isCandidateInOrgScope(candidate, orgScope))) {
79	        return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
80	      }
81	    }
82	
83	    // Load both records for side-by-side comparison
84	    let recordA = null;
85	    let recordB = null;
86	    if (candidate.recordType === 'offering') {
87	      recordA = await offeringRepo.findByIdWithAddons(candidate.recordAId);
88	      recordB = await offeringRepo.findByIdWithAddons(candidate.recordBId);
89	    } else if (candidate.recordType === 'portfolio_item') {
90	      recordA = await portfolioRepo.findById(candidate.recordAId);
91	      recordB = await portfolioRepo.findById(candidate.recordBId);
92	    }
93	
94	    return reply.status(200).send({ candidate, recordA, recordB });
95	  });
96	
97	  // POST /dedup/:candidateId/merge
98	  fastify.post('/:candidateId/merge', {
99	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'merge')],
100	  }, async (request, reply) => {
101	    const { candidateId } = request.params as { candidateId: string };
102	    const { survivingRecordId, mergedRecordId } = request.body as { survivingRecordId: string; mergedRecordId: string };
103	
104	    if (!survivingRecordId || !mergedRecordId) {
105	      return reply.status(400).send({ error: 'VALIDATION_ERROR', message: 'survivingRecordId and mergedRecordId are required' });
106	    }
107	
108	    if (survivingRecordId === mergedRecordId) {
109	      return reply.status(422).send({ error: 'SELF_MERGE_NOT_ALLOWED', message: 'Cannot merge a record with itself' });
110	    }
111	
112	    const candidate = await cleansingRepo.findCandidateById(candidateId);
113	    if (!candidate) {
114	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
115	    }
116	
117	    if (candidate.status !== 'pending') {
118	      return reply.status(409).send({ error: 'CANDIDATE_ALREADY_RESOLVED', message: `Candidate is already ${candidate.status}`, currentStatus: candidate.status });
119	    }
120	
121	    // Org-scope check for non-admin users
122	    if (request.user.role !== 'administrator') {
123	      const orgScope = request.authContext?.orgScope ?? [];
124	      if (!(await isCandidateInOrgScope(candidate, orgScope))) {
125	        return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
126	      }
127	    }
128	
129	    // Verify records exist and belong to same org
130	    if (candidate.recordType === 'offering') {
131	      const recordA = await offeringRepo.findById(survivingRecordId);
132	      const recordB = await offeringRepo.findById(mergedRecordId);
133	
134	      if (!recordA || !recordB) {
135	        return reply.status(404).send({ error: 'RECORD_NOT_FOUND', message: 'One or both records not found' });
136	      }
137	
138	      if (recordA.orgId !== recordB.orgId) {
139	        return reply.status(422).send({ error: 'ORG_MISMATCH', message: 'Records belong to different organizations' });
140	      }
141	
142	      // Build provenance
143	      const provenance = {
144	        original_creators: [
145	          { user_id: recordB.merchantId, created_at: recordB.createdAt, org_id: recordB.orgId },
146	        ],
147	        merge_chain: [{
148	          merged_id: mergedRecordId,
149	          surviving_id: survivingRecordId,
150	          merged_by: request.user.sub,
151	          merged_at: new Date().toISOString(),
152	        }],
153	        snapshot: recordB,
154	      };
155	
156	      // Record merge history
157	      await cleansingRepo.createMergeHistory({
158	        duplicateCandidateId: candidateId,
159	        survivingId: survivingRecordId,
160	        mergedId: mergedRecordId,
161	        provenance,
162	        performedBy: request.user.sub,
163	      });
164	
165	      // Soft-delete the merged offering (archive it)
166	      await offeringRepo.updateStatus(mergedRecordId, 'archived');
167	    }
168	
169	    // Update candidate status
170	    await cleansingRepo.updateCandidateStatus(candidateId, 'merged', request.user.sub);
171	
172	    request.auditContext = {
173	      resourceType: 'duplicate_candidate',
174	      resourceId: candidateId,
175	      afterState: { status: 'merged', survivingRecordId, mergedRecordId },
176	    };
177	
178	    return reply.status(200).send({
179	      candidateId,
180	      status: 'merged',
181	      survivingRecordId,
182	      mergedRecordId,
183	    });
184	  });
185	
186	  // POST /dedup/:candidateId/dismiss
187	  fastify.post('/:candidateId/dismiss', {
188	    preHandler: [fastify.authenticate, fastify.authorize('dedup', 'review')],
189	  }, async (request, reply) => {
190	    const { candidateId } = request.params as { candidateId: string };
191	
192	    const candidate = await cleansingRepo.findCandidateById(candidateId);
193	    if (!candidate) {
194	      return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
195	    }
196	
197	    // Org-scope check for non-admin users
198	    if (request.user.role !== 'administrator') {
199	      const orgScope = request.authContext?.orgScope ?? [];
200	      if (!(await isCandidateInOrgScope(candidate, orgScope))) {
201	        return reply.status(404).send({ error: 'DUPLICATE_CANDIDATE_NOT_FOUND', message: 'Candidate not found' });
202	      }
203	    }
204	
205	    if (candidate.status !== 'pending') {
206	      return reply.status(409).send({ error: 'CANDIDATE_ALREADY_RESOLVED', message: `Candidate is already ${candidate.status}`, currentStatus: candidate.status });
207	    }
208	
209	    await cleansingRepo.updateCandidateStatus(candidateId, 'dismissed', request.user.sub);
210	
211	    request.auditContext = {
212	      resourceType: 'duplicate_candidate',
213	      resourceId: candidateId,
214	      afterState: { status: 'dismissed' },
215	    };
216	
217	    return reply.status(200).send({ candidateId, status: 'dismissed' });
218	  });
219	
220	  // Helper: check if a data-quality flag's record is within org scope
221	  async function isFlagInOrgScope(flag: { recordType: string; recordId: string }, orgScope: string[]): Promise<boolean> {
222	    const orgId = await getRecordOrgId(flag.recordType, flag.recordId);
223	    if (!orgId) return false;
224	    return orgScope.includes(orgId);
225	  }
226	
227	  // GET /data-quality/flags
228	  fastify.get('/data-quality/flags', {
229	    preHandler: [fastify.authenticate, fastify.authorize('data_quality', 'review')],
230	  }, async (request, reply) => {
231	    const query = request.query as { status?: string; recordType?: string; page?: string; limit?: string };
232	    const page = Math.max(1, parseInt(query.page || '1', 10));
233	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
234	
235	    const result = await cleansingRepo.listFlags({
236	      status: query.status || 'open',
237	      recordType: query.recordType,
238	      page,
239	      limit,
240	    });
241	
242	    // Filter by org scope for non-admin users
243	    let data = result.data;
244	    if (request.user.role !== 'administrator') {
245	      const orgScope = request.authContext?.orgScope ?? [];
246	      const filtered = [];
247	      for (const flag of data) {
248	        if (await isFlagInOrgScope(flag, orgScope)) {
249	          filtered.push(flag);
250	        }
251	      }
252	      data = filtered;
253	    }
254	
255	    return reply.status(200).send({
256	      data,
257	      meta: { page, limit, total: data.length, totalPages: Math.ceil(result.total / limit) },
258	    });
259	  });
260	
261	  // POST /data-quality/flags/:id/resolve
262	  fastify.post('/data-quality/flags/:id/resolve', {
263	    preHandler: [fastify.authenticate, fastify.authorize('data_quality', 'resolve')],
264	  }, async (request, reply) => {
265	    const { id } = request.params as { id: string };
266	
267	    // Org-scope check for non-admin users
268	    if (request.user.role !== 'administrator') {
269	      const flag = await cleansingRepo.findFlagById(id);
270	      if (flag) {
271	        const orgScope = request.authContext?.orgScope ?? [];
272	        if (!(await isFlagInOrgScope(flag, orgScope))) {
273	          return reply.status(404).send({ error: 'FLAG_NOT_FOUND', message: 'Flag not found' });
274	        }
275	      }
276	    }
277	
278	    await cleansingRepo.resolveFlag(id, request.user.sub);
279	    return reply.status(200).send({ id, status: 'resolved' });
280	  });
281	}
