3	const configSchema = z.object({
4	  DATABASE_URL: z.string().min(1, 'DATABASE_URL is required'),
5	  PORT: z.coerce.number().int().positive().default(3000),
6	  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),
7	  LOG_LEVEL: z.enum(['debug', 'info', 'warn', 'error']).default('info'),
8	  CORS_ORIGIN: z.string().default('http://localhost:4200'),
9	  JWT_SECRET: z.string().min(32, 'JWT_SECRET must be at least 32 characters').default('dev_jwt_secret_change_me_at_least_32_characters_long'),
10	  ENCRYPTION_KEY: z.string().length(64, 'ENCRYPTION_KEY must be 64 hex characters (32 bytes)').default('0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef'),
11	  STORAGE_ROOT: z.string().default('./data/media'),
12	});
13	
14	export type AppConfig = z.infer<typeof configSchema>;
15	
16	export function parseConfig(env: Record<string, string | undefined> = process.env): AppConfig {
17	  const result = configSchema.safeParse(env);
18	  if (!result.success) {
19	    const errors = result.error.issues.map(i => `${i.path.join('.')}: ${i.message}`);
20	    throw new Error(`Configuration validation failed:\n${errors.join('\n')}`);
21	  }
22	  return result.data;
23	}
