1	import { randomUUID } from 'node:crypto';
2	import { SESSION } from '@studioops/shared';
3	import { hashRefreshToken, generateRefreshToken } from '../domain/refresh-token';
4	import type { SessionRepositoryPort } from '../ports/session-repository.port';
5	import { AuthenticationError } from './login';
6	
7	export interface RefreshInput {
8	  refreshToken: string;
9	}
10	
11	export interface RefreshResult {
12	  accessTokenPayload: { sub: string; role: string; jti: string };
13	  refreshToken: string;
14	  expiresIn: number;
15	}
16	
17	export class RefreshUseCase {
18	  constructor(
19	    private sessionRepo: SessionRepositoryPort,
20	    private getUserRole: (userId: string) => Promise<string | null>,
21	  ) {}
22	
23	  async execute(input: RefreshInput): Promise<RefreshResult> {
24	    const tokenHash = hashRefreshToken(input.refreshToken);
25	    const storedToken = await this.sessionRepo.findRefreshTokenByHash(tokenHash);
26	
27	    if (!storedToken) {
28	      throw new AuthenticationError('Invalid or expired refresh token');
29	    }
30	
31	    if (storedToken.used) {
32	      // Token reuse detected — possible replay attack. Revoke all sessions for this user.
33	      const session = await this.sessionRepo.findSessionById(storedToken.sessionId);
34	      if (session) {
35	        await this.sessionRepo.revokeAllRefreshTokensForUser(session.userId);
36	      }
37	      throw new AuthenticationError('Invalid or expired refresh token');
38	    }
39	
40	    const now = new Date();
41	
42	    if (storedToken.expiresAt < now) {
43	      throw new AuthenticationError('Invalid or expired refresh token');
44	    }
45	
46	    if (storedToken.absoluteExpiresAt < now) {
47	      throw new AuthenticationError('Session expired, please log in again');
48	    }
49	
50	    // Mark old token as used
51	    await this.sessionRepo.markRefreshTokenUsed(storedToken.id);
52	
53	    // Look up session to get userId
54	    const session = await this.sessionRepo.findSessionById(storedToken.sessionId);
55	    if (!session || session.revoked) {
56	      throw new AuthenticationError('Session revoked');
57	    }
58	
59	    const role = await this.getUserRole(session.userId);
60	    if (!role) {
61	      throw new AuthenticationError('User not found');
62	    }
63	
64	    // Issue new tokens with sliding session (8hr window from now)
65	    const jti = randomUUID();
66	    const newRefreshTokenPair = generateRefreshToken();
67	    const refreshExpiresAt = new Date(now.getTime() + SESSION.REFRESH_TOKEN_LIFETIME_SECONDS * 1000);
68	    const slidingAbsoluteExpiry = new Date(now.getTime() + SESSION.ABSOLUTE_SESSION_LIFETIME_SECONDS * 1000);
69	
70	    // Update session's tokenJti so auth middleware can find it
71	    await this.sessionRepo.updateSessionTokenJti(session.id, jti);
72	
73	    await this.sessionRepo.createRefreshToken({
74	      sessionId: session.id,
75	      tokenHash: newRefreshTokenPair.hash,
76	      expiresAt: refreshExpiresAt,
77	      absoluteExpiresAt: slidingAbsoluteExpiry, // sliding: 8hr window resets on each refresh
78	    });
79	
80	    return {
81	      accessTokenPayload: { sub: session.userId, role, jti },
82	      refreshToken: newRefreshTokenPair.plaintext,
83	      expiresIn: SESSION.ACCESS_TOKEN_LIFETIME_SECONDS,
84	    };
85	  }
86	}
