2	import fp from 'fastify-plugin';
3	import jwt from '@fastify/jwt';
4	import { eq, and } from 'drizzle-orm';
5	import { sessions } from '@studioops/db/schema';
6	
7	declare module 'fastify' {
8	  interface FastifyInstance {
9	    authenticate: (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
10	    optionalAuthenticate: (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
11	  }
12	}
13	
14	declare module '@fastify/jwt' {
15	  interface FastifyJWT {
16	    payload: { sub: string; role: string; jti: string };
17	    user: { sub: string; role: string; jti: string };
18	  }
19	}
20	
21	interface AuthPluginOptions {
22	  jwtSecret: string;
23	}
24	
25	async function authPlugin(fastify: FastifyInstance, opts: AuthPluginOptions) {
26	  await fastify.register(jwt, {
27	    secret: opts.jwtSecret,
28	    sign: {
29	      expiresIn: '30m',
30	    },
31	  });
32	
33	  fastify.decorate('authenticate', async function (request: FastifyRequest, reply: FastifyReply) {
34	    try {
35	      await request.jwtVerify();
36	    } catch (err) {
37	      return reply.status(401).send({
38	        error: 'UNAUTHORIZED',
39	        message: 'Invalid or expired token',
40	      });
41	    }
42	
43	    // Validate session: look up by jti, reject if revoked or expired
44	    const jti = request.user.jti;
45	    if (jti) {
46	      try {
47	        const [session] = await fastify.db
48	          .select()
49	          .from(sessions)
50	          .where(eq(sessions.tokenJti, jti))
51	          .limit(1);
52	
53	        if (!session) {
54	          return reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Session not found' });
55	        }
56	
57	        if (session.revoked) {
58	          return reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Session has been revoked' });
59	        }
60	
61	        if (session.absoluteExpiresAt < new Date()) {
62	          return reply.status(401).send({ error: 'UNAUTHORIZED', message: 'Session expired' });
63	        }
64	
65	        // Update last activity for sliding session tracking
66	        await fastify.db
67	          .update(sessions)
68	          .set({ lastActivityAt: new Date() })
69	          .where(eq(sessions.id, session.id));
