1	import { FastifyInstance } from 'fastify';
2	import {
3	  createOfferingSchema,
4	  updateOfferingSchema,
5	  changeOfferingStatusSchema,
6	  createAddonSchema,
7	  grantAccessSchema,
8	} from '@studioops/shared';
9	import { validateStatusTransition, isArchived } from '../../core/domain/offering';
10	import { DrizzleOfferingRepository } from '../../infrastructure/persistence/offering-repository';
11	import { DrizzleCleansingRepository } from '../../infrastructure/persistence/cleansing-repository';
12	import { autoCleanseRecord } from '../../core/use-cases/auto-cleanse';
13	import type { Role } from '@studioops/shared';
14	
15	export default async function offeringRoutes(fastify: FastifyInstance) {
16	  const offeringRepo = new DrizzleOfferingRepository(fastify.db);
17	  const cleansingRepo = new DrizzleCleansingRepository(fastify.db);
18	
19	  // POST /offerings
20	  fastify.post('/', {
21	    preHandler: [fastify.authenticate, fastify.authorize('offering', 'create')],
22	  }, async (request, reply) => {
23	    const parseResult = createOfferingSchema.safeParse(request.body);
24	    if (!parseResult.success) {
25	      return reply.status(400).send({
26	        error: 'VALIDATION_ERROR',
27	        message: 'Validation failed',
28	        details: parseResult.error.issues.map((i) => i.message),
29	      });
30	    }
31	
32	    const { orgId, ...rest } = parseResult.data;
33	
34	    // Verify merchant is in org
35	    if (request.authContext?.orgScope && !request.authContext.orgScope.includes(orgId)) {
36	      return reply.status(403).send({
37	        error: 'FORBIDDEN',
38	        message: 'You are not a member of this organization',
39	      });
40	    }
41	
42	    const offering = await offeringRepo.create({
43	      ...rest,
44	      orgId,
45	      merchantId: request.user.sub,
46	    });
47	
48	    request.auditContext = {
49	      resourceType: 'offering',
50	      resourceId: offering.id,
51	      afterState: offering,
52	    };
53	
54	    // Auto-cleansing: normalize, detect outliers, find duplicates (fire-and-forget)
55	    (async () => {
56	      try {
57	        const allOfferings = await offeringRepo.list({ page: 1, limit: 200, orgId, role: 'administrator' as Role, status: 'active' });
58	        const targets = allOfferings.data.map(o => ({
59	          id: o.id, title: o.title, priceCents: o.basePriceCents,
60	          durationMinutes: o.durationMinutes, tags: [] as string[], orgId: o.orgId,
61	        }));
62	        const medianPrice = targets.length > 0
63	          ? targets.map(t => t.priceCents).sort((a, b) => a - b)[Math.floor(targets.length / 2)]
64	          : 0;
65	
66	        const result = autoCleanseRecord(
67	          { id: offering.id, title: offering.title, priceCents: offering.basePriceCents, durationMinutes: offering.durationMinutes, tags: [], orgId },
68	          targets, medianPrice,
69	        );
70	
71	        for (const flag of result.flags) {
72	          await cleansingRepo.createFlag({ recordType: 'offering', recordId: offering.id, field: flag.field, issue: flag.issue, detail: flag.detail });
73	        }
74	        for (const dup of result.duplicateCandidates) {
75	          await cleansingRepo.createCandidate({ recordType: 'offering', recordAId: offering.id, recordBId: dup.existingId, similarityScore: dup.score, featureScores: dup.featureScores });
76	        }
77	      } catch (err) {
78	        fastify.log.error({ err, offeringId: offering.id }, 'Auto-cleansing failed');
79	      }
80	    })();
81	
82	    return reply.status(201).send(offering);
83	  });
84	
85	  // GET /offerings (optional auth — guests can browse public)
86	  fastify.get('/', {
87	    preHandler: [fastify.optionalAuthenticate, async (request) => {
88	      // If authenticated, populate orgScope for tenant isolation
89	      if (request.user?.sub) {
90	        const { DrizzlePermissionRepository } = await import('../../infrastructure/persistence/permission-repository');
91	        const permRepo = new DrizzlePermissionRepository(fastify.db);
92	        const orgIds = await permRepo.getOrgIdsForUser(request.user.sub);
93	        request.authContext = { userId: request.user.sub, role: request.user.role as Role, orgScope: orgIds };
94	      }
95	    }],
96	  }, async (request, reply) => {
97	    const query = request.query as { page?: string; limit?: string; orgId?: string; status?: string };
98	    const page = Math.max(1, parseInt(query.page || '1', 10));
99	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
100	
101	    const role = (request.user?.role || 'guest') as Role;
102	    const userId = request.user?.sub;
103	    // Non-admin authenticated users: always pass orgScope ([] if none). Guests: undefined.
104	    const orgScope = request.user
105	      ? (role === 'administrator' ? undefined : (request.authContext?.orgScope ?? []))
106	      : undefined;
107	
108	    const result = await offeringRepo.list({
109	      page,
110	      limit,
111	      orgId: query.orgId,
112	      status: query.status as any,
113	      role,
114	      userId,
115	      orgScope,
116	    });
117	
118	    return reply.status(200).send({
119	      data: result.data,
120	      meta: {
121	        page,
122	        limit,
123	        total: result.total,
124	        totalPages: Math.ceil(result.total / limit),
125	      },
126	    });
127	  });
128	
129	  // GET /offerings/:id (optional auth)
130	  fastify.get('/:id', {
131	    preHandler: [fastify.optionalAuthenticate, async (request) => {
132	      if (request.user?.sub) {
133	        const { DrizzlePermissionRepository } = await import('../../infrastructure/persistence/permission-repository');
134	        const permRepo = new DrizzlePermissionRepository(fastify.db);
135	        const orgIds = await permRepo.getOrgIdsForUser(request.user.sub);
136	        request.authContext = { userId: request.user.sub, role: request.user.role as Role, orgScope: orgIds };
137	      }
138	    }],
139	  }, async (request, reply) => {
140	    const { id } = request.params as { id: string };
141	    const offering = await offeringRepo.findByIdWithAddons(id);
142	
143	    if (!offering) {
144	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Offering not found' });
145	    }
146	
147	    // Visibility + org-scope check
148	    const role = (request.user?.role || 'guest') as Role;
149	
150	    // Operations: enforce org scope
151	    if (role === 'operations') {
152	      const orgScope = request.authContext?.orgScope ?? [];
153	      if (!orgScope.includes(offering.orgId)) {
154	        return reply.status(404).send({ error: 'NOT_FOUND', message: 'Offering not found' });
155	      }
156	    }
157	
158	    if (role !== 'administrator' && role !== 'operations') {
159	      if (offering.visibility === 'private' && offering.merchantId !== request.user?.sub) {
160	        return reply.status(404).send({ error: 'NOT_FOUND', message: 'Offering not found' });
161	      }
162	      if (offering.visibility === 'restricted') {
163	        const hasAccess = request.user?.sub
164	          ? await offeringRepo.hasAccess(id, request.user.sub)
165	          : false;
166	        if (!hasAccess && offering.merchantId !== request.user?.sub) {
167	          return reply.status(404).send({ error: 'NOT_FOUND', message: 'Offering not found' });
168	        }
169	      }
170	    }
171	
172	    return reply.status(200).send(offering);
173	  });
174	
175	  // PUT /offerings/:id
176	  fastify.put('/:id', {
177	    preHandler: [fastify.authenticate, fastify.authorize('offering', 'update'), fastify.enforceQuota('hourly_edit_limit')],
178	  }, async (request, reply) => {
179	    const { id } = request.params as { id: string };
180	    const parseResult = updateOfferingSchema.safeParse(request.body);
181	    if (!parseResult.success) {
182	      return reply.status(400).send({
183	        error: 'VALIDATION_ERROR',
184	        message: 'Validation failed',
185	        details: parseResult.error.issues.map((i) => i.message),
186	      });
187	    }
188	
189	    const existing = await offeringRepo.findById(id);
190	    if (!existing) {
191	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Offering not found' });
192	    }
193	
194	    // Ownership check for merchant
195	    if (request.user.role === 'merchant' && existing.merchantId !== request.user.sub) {
196	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'You do not own this resource' });
197	    }
198	
199	    if (isArchived(existing.status)) {
200	      return reply.status(409).send({ error: 'CONFLICT', message: 'Cannot modify an archived offering' });
201	    }
202	
203	    const updated = await offeringRepo.update(id, parseResult.data);
204	
205	    request.auditContext = {
206	      resourceType: 'offering',
207	      resourceId: id,
208	      beforeState: existing,
209	      afterState: updated,
210	    };
211	
212	    return reply.status(200).send(updated);
213	  });
214	
215	  // PATCH /offerings/:id/status
216	  fastify.patch('/:id/status', {
217	    preHandler: [fastify.authenticate, fastify.authorize('offering', 'update')],
218	  }, async (request, reply) => {
219	    const { id } = request.params as { id: string };
220	    const parseResult = changeOfferingStatusSchema.safeParse(request.body);
221	    if (!parseResult.success) {
222	      return reply.status(400).send({
223	        error: 'VALIDATION_ERROR',
224	        message: 'Validation failed',
225	        details: parseResult.error.issues.map((i) => i.message),
226	      });
227	    }
228	
229	    const existing = await offeringRepo.findById(id);
230	    if (!existing) {
231	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Offering not found' });
232	    }
233	
234	    if (request.user.role === 'merchant' && existing.merchantId !== request.user.sub) {
235	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'You do not own this resource' });
236	    }
237	
238	    const transition = validateStatusTransition(existing.status, parseResult.data.status);
239	    if (!transition.valid) {
240	      return reply.status(409).send({
241	        error: 'INVALID_TRANSITION',
242	        message: transition.error,
243	      });
244	    }
245	
246	    const updated = await offeringRepo.updateStatus(id, parseResult.data.status);
247	
248	    request.auditContext = {
249	      resourceType: 'offering',
250	      resourceId: id,
251	      beforeState: { status: existing.status },
252	      afterState: { status: updated.status },
253	    };
254	
255	    return reply.status(200).send(updated);
256	  });
257	
258	  // POST /offerings/:id/addons
259	  fastify.post('/:id/addons', {
260	    preHandler: [fastify.authenticate, fastify.authorize('offering', 'update')],
261	  }, async (request, reply) => {
262	    const { id } = request.params as { id: string };
263	    const parseResult = createAddonSchema.safeParse(request.body);
264	    if (!parseResult.success) {
265	      return reply.status(400).send({
266	        error: 'VALIDATION_ERROR',
267	        message: 'Validation failed',
268	        details: parseResult.error.issues.map((i) => i.message),
269	      });
270	    }
271	
272	    const existing = await offeringRepo.findById(id);
273	    if (!existing) {
274	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Offering not found' });
275	    }
276	
277	    if (request.user.role === 'merchant' && existing.merchantId !== request.user.sub) {
278	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'You do not own this resource' });
279	    }
280	
281	    try {
282	      const addon = await offeringRepo.createAddon(id, parseResult.data);
283	      request.auditContext = { resourceType: 'offering_addon', resourceId: addon.id, afterState: addon };
284	      return reply.status(201).send(addon);
285	    } catch (err: any) {
286	      if (err.code === '23505') { // unique violation
287	        return reply.status(409).send({ error: 'CONFLICT', message: 'Add-on with this name already exists' });
288	      }
289	      throw err;
290	    }
291	  });
