236	    const { id } = request.params as { id: string };
237	    const { tagNames } = request.body as { tagNames?: string[] };
238	
239	    if (!tagNames || !Array.isArray(tagNames)) {
240	      return reply.status(400).send({ error: 'VALIDATION_ERROR', message: 'tagNames array is required' });
