247	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'You do not own this resource' });
248	    }
249	
250	    const tagRecords = await Promise.all(tagNames.map((name) => portfolioRepo.getOrCreateTag(name)));
251	    await portfolioRepo.setItemTags(id, tagRecords.map((t) => t.id));
252	
253	    const tags = await portfolioRepo.getItemTags(id);
