1	import { drizzle } from 'drizzle-orm/postgres-js';
2	import postgres from 'postgres';
3	import { eq, and, sql } from 'drizzle-orm';
4	import argon2 from 'argon2';
5	import * as schema from './schema/index';
6	import { seed as seedPermissions } from './seed';
7	
8	async function hashPassword(password: string): Promise<string> {
9	  return argon2.hash(password, { type: argon2.argon2id, memoryCost: 65536, timeCost: 3, parallelism: 4 });
10	}
11	
12	export async function seedFull(connectionString: string) {
13	  // First seed permissions
14	  await seedPermissions(connectionString);
15	
16	  const client = postgres(connectionString, { max: 1 });
17	  const db = drizzle(client, { schema });
18	
19	  console.log('Seeding full dataset...');
20	
21	  // Get org
22	  const [org] = await db.select().from(schema.organizations).where(eq(schema.organizations.slug, 'default-studio')).limit(1);
23	  const orgId = org.id;
24	
25	  // Seed users
26	  const users = [
27	    { username: 'admin', password: 'AdminPass123!@', role: 'administrator' as const },
28	    { username: 'ops_user', password: 'OpsUserPass123!@', role: 'operations' as const },
29	    { username: 'merchant1', password: 'MerchantPass123!@', role: 'merchant' as const },
30	    { username: 'client1', password: 'ClientPass123!@', role: 'client' as const },
31	  ];
32	
33	  for (const u of users) {
34	    const existing = await db.select().from(schema.users).where(eq(schema.users.username, u.username)).limit(1);
35	    if (existing.length > 0) {
36	      console.log(`  User '${u.username}' already exists`);
37	      continue;
38	    }
39	
40	    const hash = await hashPassword(u.password);
41	    const [user] = await db.insert(schema.users).values({
42	      username: u.username,
43	      passwordHash: hash,
44	      role: u.role,
45	      orgId,
46	    }).returning();
47	
48	    // Add to org
49	    await db.insert(schema.organizationMembers).values({
50	      orgId,
51	      userId: user.id,
52	      roleInOrg: u.role === 'administrator' ? 'owner' : 'member',
53	    }).onConflictDoNothing();
54	
55	    console.log(`  Created user '${u.username}' (${u.role})`);
56	  }
57	
58	  // Get merchant ID for sample data
59	  const [merchant] = await db.select().from(schema.users).where(eq(schema.users.username, 'merchant1')).limit(1);
60	  const [clientUser] = await db.select().from(schema.users).where(eq(schema.users.username, 'client1')).limit(1);
61	
62	  // Seed sample offerings
63	  const offeringsData = [
64	    { title: 'Wedding Essentials', description: 'Full-day wedding coverage', basePriceCents: 250000, durationMinutes: 360, visibility: 'public' as const, status: 'active' as const },
65	    { title: 'Corporate Headshots', description: 'Professional headshot session', basePriceCents: 45000, durationMinutes: 90, visibility: 'public' as const, status: 'active' as const },
66	    { title: 'Portrait Session', description: 'Individual or family portraits', basePriceCents: 35000, durationMinutes: 60, visibility: 'public' as const, status: 'draft' as const },
67	  ];
68	
69	  for (const o of offeringsData) {
70	    const existing = await db.select().from(schema.offerings).where(eq(schema.offerings.title, o.title)).limit(1);
71	    if (existing.length > 0) continue;
72	
73	    const [offering] = await db.insert(schema.offerings).values({
74	      orgId,
75	      merchantId: merchant.id,
76	      title: o.title,
77	      description: o.description,
78	      basePriceCents: o.basePriceCents,
79	      durationMinutes: o.durationMinutes,
80	      visibility: o.visibility,
81	      status: o.status,
82	    }).returning();
83	
84	    // Add addons to Wedding package
85	    if (o.title === 'Wedding Essentials') {
86	      await db.insert(schema.offeringAddons).values([
87	        { offeringId: offering.id, name: 'Extra Retouched Images', priceCents: 1500, unitDescription: 'each' },
88	        { offeringId: offering.id, name: 'Second Shooter', priceCents: 8000, unitDescription: 'per hour' },
89	      ]).onConflictDoNothing();
90	    }
91	
92	    console.log(`  Created offering '${o.title}'`);
93	  }
94	
95	  // Seed sample events
96	  const eventsData = [
97	    { title: 'Smith Wedding', eventType: 'wedding', scheduledAt: new Date('2026-06-15T10:00:00Z'), durationMinutes: 480, channel: 'referral', tags: ['wedding', 'outdoor'] },
98	    { title: 'Corp Headshot Day', eventType: 'corporate', scheduledAt: new Date('2026-06-20T09:00:00Z'), durationMinutes: 120, channel: 'website', tags: ['corporate', 'studio'] },
99	    { title: 'Johnson Family', eventType: 'portrait', scheduledAt: new Date('2026-07-01T14:00:00Z'), durationMinutes: 90, channel: 'walk-in', tags: ['portrait', 'family'] },
100	    { title: 'Lee Wedding', eventType: 'wedding', scheduledAt: new Date('2026-07-10T11:00:00Z'), durationMinutes: 360, channel: 'referral', tags: ['wedding', 'indoor'] },
101	    { title: 'Tech Corp Shots', eventType: 'corporate', scheduledAt: new Date('2026-07-15T09:00:00Z'), durationMinutes: 180, channel: 'website', tags: ['corporate', 'team'] },
102	  ];
103	
104	  for (const e of eventsData) {
105	    const existing = await db.select().from(schema.events).where(eq(schema.events.title, e.title)).limit(1);
106	    if (existing.length > 0) continue;
107	
108	    const [event] = await db.insert(schema.events).values({
109	      orgId,
110	      merchantId: merchant.id,
111	      title: e.title,
112	      eventType: e.eventType,
113	      scheduledAt: e.scheduledAt,
114	      durationMinutes: e.durationMinutes,
115	      channel: e.channel,
116	      tags: e.tags,
117	      status: 'confirmed',
118	    }).returning();
119	
120	    // Add a registration for the client
121	    await db.insert(schema.registrations).values({
122	      eventId: event.id,
123	      clientId: clientUser.id,
124	      status: 'confirmed',
125	      confirmedAt: new Date(),
126	    }).onConflictDoNothing();
127	
128	    console.log(`  Created event '${e.title}'`);
129	  }
130	
131	  console.log('Full seed complete.');
132	  await client.end();
133	}
134	
135	// Run directly
136	const dbUrl = process.env.DATABASE_URL;
137	if (dbUrl) {
138	  seedFull(dbUrl).catch((err) => {
139	    console.error('Full seed failed:', err);
140	    process.exit(1);
141	  });
142	}
