1	#!/usr/bin/env node
2	
3	/**
4	 * Cross-platform test runner for StudioOps.
5	 * Runs: unit tests → integration tests → Angular build check → E2E tests (if API running).
6	 * Usage: node scripts/run-tests.js
7	 */
8	
9	import { execSync } from 'node:child_process';
10	import { resolve } from 'node:path';
11	
12	const root = resolve(import.meta.dirname, '..');
13	
14	function run(label, cmd, cwd = root) {
15	  console.log(`\n--- ${label} ---`);
16	  try {
17	    execSync(cmd, { cwd, stdio: 'inherit', env: { ...process.env, FORCE_COLOR: '1' } });
18	    console.log(`✓ ${label} passed`);
19	  } catch {
20	    console.error(`✗ ${label} FAILED`);
21	    process.exit(1);
22	  }
23	}
24	
25	console.log('=== StudioOps Test Suite ===\n');
26	
27	// 1. Unit tests
28	run('[1/4] API Unit Tests', 'npx vitest run', resolve(root, 'apps/api'));
29	
30	// 2. Integration tests (requires DATABASE_URL)
31	if (process.env.DATABASE_URL) {
32	  run('[2/4] API Integration Tests', 'npx vitest run --config vitest.integration.config.ts', resolve(root, 'apps/api'));
33	} else {
34	  console.log('\n--- [2/4] API Integration Tests ---');
35	  console.log('⚠ Skipped (DATABASE_URL not set). Set DATABASE_URL to run integration tests.');
36	}
37	
38	// 3. Angular build
39	run('[3/4] Angular Build Check', 'npx ng build --configuration=production', resolve(root, 'apps/web'));
40	
41	// 4. E2E tests (if API is running)
42	const apiUrl = process.env.API_URL || 'http://localhost:3000';
43	try {
44	  const http = await import('node:http');
45	  await new Promise((resolve, reject) => {
46	    http.get(`${apiUrl}/api/v1/health`, (res) => {
47	      if (res.statusCode === 200) resolve(true);
48	      else reject(new Error(`API returned ${res.statusCode}`));
49	    }).on('error', reject);
50	  });
51	  run('[4/4] Playwright E2E Tests', `npx playwright test --config e2e/playwright.config.ts --project=api`, root);
52	} catch {
53	  console.log('\n--- [4/4] Playwright E2E Tests ---');
54	  console.log(`⚠ Skipped (API not reachable at ${apiUrl}). Start API to run E2E tests.`);
55	}
56	
57	console.log('\n=== All available tests passed ===');
58

