1	import { QUOTAS } from '@studioops/shared';
2	import {
3	  resolveRuleVersion,
4	  getWindowSeconds,
5	  QuotaExceededError,
6	  CooldownError,
7	  type RuleConfig,
8	} from '../domain/rules-engine';
9	import { isAdminRole } from '../domain/permissions';
10	import type { RulesRepositoryPort } from '../ports/rules-repository.port';
11	import type { LockoutRepositoryPort } from '../ports/lockout-repository.port';
12	import type { Role } from '@studioops/shared';
13	
14	export interface EnforceQuotaInput {
15	  userId: string;
16	  role: Role;
17	  ruleKey: string;
18	}
19	
20	export class EnforceQuotaUseCase {
21	  constructor(
22	    private rulesRepo: RulesRepositoryPort,
23	    private lockoutRepo: LockoutRepositoryPort,
24	  ) {}
25	
26	  async execute(input: EnforceQuotaInput): Promise<void> {
27	    const { userId, role, ruleKey } = input;
28	
29	    // Admin always bypasses quotas
30	    if (isAdminRole(role)) return;
31	
32	    // Check whitelist
33	    const whitelisted = await this.rulesRepo.isWhitelisted(userId, ruleKey);
34	    if (whitelisted) return;
35	
36	    // Check if user has an active penalty
37	    const activePenalty = await this.lockoutRepo.getActiveLockout(userId);
38	    if (activePenalty && activePenalty.restrictionType === 'penalty' && activePenalty.expiresAt && activePenalty.expiresAt > new Date()) {
39	      const retryAfter = Math.ceil((activePenalty.expiresAt.getTime() - Date.now()) / 1000);
40	      throw new QuotaExceededError(ruleKey, 0, 0, retryAfter);
41	    }
42	
43	    // Load rule versions (newest first)
44	    const versions = await this.rulesRepo.getActiveVersions(ruleKey);
45	    if (versions.length === 0) return; // No rule = no quota
46	
47	    const rule = resolveRuleVersion(versions, userId);
48	    if (!rule) return; // No matching version (user outside canary)
49	
50	    const config = rule.config as RuleConfig;
51	
52	    // Cooldown check
53	    if (config.cooldownSeconds) {
54	      const lastAction = await this.rulesRepo.getLastActionTimestamp(userId, ruleKey);
55	      if (lastAction) {
56	        const elapsed = (Date.now() - lastAction.getTime()) / 1000;
57	        if (elapsed < config.cooldownSeconds) {
58	          const retryAfter = Math.ceil(config.cooldownSeconds - elapsed);
59	          throw new CooldownError(retryAfter);
60	        }
61	      }
62	    }
63	
64	    // Quota check
65	    const windowSec = getWindowSeconds(config.window);
66	    const currentCount = await this.rulesRepo.getUserActionCount(userId, ruleKey, windowSec);
67	
68	    if (currentCount >= config.limit) {
69	      // Record violation
70	      await this.rulesRepo.recordViolation(userId, ruleKey);
71	
72	      // Check escalation: 3 violations in 24h → 30min penalty
73	      const violationCount = await this.rulesRepo.getViolationCount(userId, 86400);
74	      if (violationCount >= QUOTAS.VIOLATION_THRESHOLD) {
75	        const penaltyExpiry = new Date(Date.now() + QUOTAS.PENALTY_DURATION_SECONDS * 1000);
76	        await this.lockoutRepo.createLockout(
77	          userId,
78	          penaltyExpiry,
79	          `${violationCount} quota violations in 24 hours`,
80	          'penalty',
81	        );
82	      }
