62	export async function seed(connectionString: string) {
63	  const client = postgres(connectionString, { max: 1 });
64	  const db = drizzle(client, { schema });
65	
66	  console.log('Seeding permissions...');
67	
68	  // Upsert permissions
69	  for (const perm of PERMISSIONS_MANIFEST) {
70	    const existing = await db
71	      .select()
72	      .from(schema.permissions)
73	      .where(and(
74	        eq(schema.permissions.resource, perm.resource),
75	        eq(schema.permissions.action, perm.action),
76	      ))
77	      .limit(1);
78	
79	    if (existing.length === 0) {
80	      await db.insert(schema.permissions).values(perm);
81	    }
82	  }
83	
84	  // Load all permissions for ID mapping
85	  const allPerms = await db.select().from(schema.permissions);
86	  const permMap = new Map(allPerms.map((p) => [`${p.resource}:${p.action}`, p.id]));
87	
88	  // Upsert role_permissions
89	  for (const [role, permKeys] of Object.entries(ROLE_PERMISSIONS) as [RoleName, string[]][]) {
90	    for (const permKey of permKeys) {
91	      const permId = permMap.get(permKey);
92	      if (!permId) {
93	        console.warn(`Permission not found: ${permKey}`);
94	        continue;
95	      }
96	
97	      const existing = await db
98	        .select()
99	        .from(schema.rolePermissions)
100	        .where(and(
101	          eq(schema.rolePermissions.role, role),
102	          eq(schema.rolePermissions.permissionId, permId),
103	        ))
104	        .limit(1);
105	
106	      if (existing.length === 0) {
107	        await db.insert(schema.rolePermissions).values({ role, permissionId: permId });
108	      }
109	    }
110	  }
111	
112	  // Seed default organization
113	  const existingOrg = await db
114	    .select()
115	    .from(schema.organizations)
116	    .where(eq(schema.organizations.slug, 'default-studio'))
117	    .limit(1);
118	
119	  let orgId: string;
120	  if (existingOrg.length === 0) {
121	    const [org] = await db
122	      .insert(schema.organizations)
123	      .values({ name: 'Default Studio', slug: 'default-studio' })
124	      .returning();
125	    orgId = org.id;
126	    console.log('Created default organization:', orgId);
127	  } else {
128	    orgId = existingOrg[0].id;
129	    console.log('Default organization exists:', orgId);
130	  }
131	
132	  console.log('Seed complete.');
133	  await client.end();
134	  return { orgId };
135	}
136	
137	// Only auto-run when called directly as main module
138	const isMainModule = process.argv[1]?.includes('seed.ts') && !process.argv[1]?.includes('seed-full');
139	if (isMainModule) {
140	  const dbUrl = process.env.DATABASE_URL;
141	  if (dbUrl) {
142	    seed(dbUrl).catch((err) => {
143	      console.error('Seed failed:', err);
144	      process.exit(1);
145	    });
146	  }
147	}
