20	/**
21	 * Deterministic canary hash.
22	 * Uses SHA-256(userId + ruleId) mod 100. If result < canaryPercent, user is in canary.
23	 */
24	export function isInCanary(userId: string, ruleId: string, canaryPercent: number): boolean {
25	  if (canaryPercent >= 100) return true;
26	  if (canaryPercent <= 0) return false;
27	
28	  const hash = createHash('sha256').update(userId + ruleId).digest();
29	  // Take first 4 bytes as unsigned 32-bit integer
30	  const value = hash.readUInt32BE(0);
31	  const bucket = value % 100;
32	  return bucket < canaryPercent;
33	}
34	
35	/**
36	 * Resolve which rule version to apply for a given user.
37	 * Versions must be sorted by version DESC (newest first).
38	 */
39	export function resolveRuleVersion(
40	  versions: RuleVersion[],
41	  userId: string,
42	  now: Date = new Date(),
43	): RuleVersion | null {
44	  for (const rule of versions) {
45	    if (rule.status !== 'active') continue;
46	    if (rule.effectiveFrom > now) continue;
47	    if (rule.effectiveTo && rule.effectiveTo < now) continue;
48	
49	    if (isInCanary(userId, rule.id, rule.canaryPercent)) {
50	      return rule;
51	    }
52	    // If user is not in canary for this version, try the next (older) version
53	  }
54	  return null;
55	}
