18	/**
19	 * Maps rule keys to the audit log resourceType + action used for counting.
20	 * This must match what the audit-log plugin records for each route.
21	 */
22	const RULE_KEY_TO_AUDIT: Record<string, { resourceType: string; actionPattern?: string }> = {
23	  daily_upload_limit: { resourceType: 'portfolio' },
24	  hourly_edit_limit: { resourceType: 'offering' },
25	  export_cooldown: { resourceType: 'analytics' },
26	};
27	
28	class DrizzleRulesRepository implements RulesRepositoryPort {
29	  constructor(private db: any) {}
30	
31	  async getActiveVersions(ruleKey: string): Promise<RuleVersion[]> {
32	    const rows = await this.db.select().from(rules)
33	      .where(and(eq(rules.ruleKey, ruleKey), eq(rules.status, 'active')))
34	      .orderBy(desc(rules.version));
35	    return rows.map((r: any) => ({
36	      id: r.id,
37	      ruleKey: r.ruleKey,
38	      version: r.version,
39	      config: r.config,
40	      effectiveFrom: r.effectiveFrom,
41	      effectiveTo: r.effectiveTo,
42	      canaryPercent: r.canaryPercent,
43	      status: r.status,
44	    }));
45	  }
46	
47	  async getUserActionCount(userId: string, ruleKey: string, windowSeconds: number): Promise<number> {
48	    const mapping = RULE_KEY_TO_AUDIT[ruleKey];
49	    if (!mapping) return 0; // unknown rule key = no enforcement
50	    const since = new Date(Date.now() - windowSeconds * 1000);
51	    const [result] = await this.db.select({ count: sql<number>`count(*)::int` })
52	      .from(auditLogs)
53	      .where(and(
54	        eq(auditLogs.actorId, userId),
55	        eq(auditLogs.resourceType, mapping.resourceType),
56	        gt(auditLogs.createdAt, since),
57	      ));
58	    return result?.count ?? 0;
59	  }
60	
61	  async getLastActionTimestamp(userId: string, ruleKey: string): Promise<Date | null> {
62	    const mapping = RULE_KEY_TO_AUDIT[ruleKey];
63	    if (!mapping) return null;
64	    const rows = await this.db.select({ createdAt: auditLogs.createdAt })
65	      .from(auditLogs)
66	      .where(and(eq(auditLogs.actorId, userId), eq(auditLogs.resourceType, mapping.resourceType)))
67	      .orderBy(desc(auditLogs.createdAt))
68	      .limit(1);
69	    return rows[0]?.createdAt ?? null;
70	  }
71	
72	  async isWhitelisted(userId: string, ruleKey: string): Promise<boolean> {
73	    const rows = await this.db.select().from(ruleWhitelist)
74	      .where(and(eq(ruleWhitelist.userId, userId), eq(ruleWhitelist.ruleKey, ruleKey)))
75	      .limit(1);
76	    return rows.length > 0;
77	  }
78	
79	  async recordViolation(userId: string, ruleKey: string): Promise<void> {
80	    await this.db.insert(userViolations).values({ userId, ruleKey });
81	  }
82	
83	  async getViolationCount(userId: string, windowSeconds: number): Promise<number> {
84	    const since = new Date(Date.now() - windowSeconds * 1000);
85	    const [result] = await this.db.select({ count: sql<number>`count(*)::int` })
86	      .from(userViolations)
87	      .where(and(eq(userViolations.userId, userId), gt(userViolations.createdAt, since)));
88	    return result?.count ?? 0;
89	  }
90	}
