92	async function rulesEnginePlugin(fastify: FastifyInstance) {
93	  const rulesRepo = new DrizzleRulesRepository(fastify.db);
94	  const lockoutRepo = new DrizzleLockoutRepository(fastify.db);
95	  const enforceQuota = new EnforceQuotaUseCase(rulesRepo, lockoutRepo);
96	
97	  fastify.decorate('enforceQuota', function (ruleKey: string) {
98	    return async function (request: FastifyRequest, reply: FastifyReply) {
99	      if (!request.user?.sub) return; // unauthenticated = skip
100	
101	      try {
102	        await enforceQuota.execute({
103	          userId: request.user.sub,
104	          role: request.user.role as Role,
105	          ruleKey,
106	        });
107	      } catch (err) {
108	        if (err instanceof QuotaExceededError) {
109	          return reply.status(429).send({
110	            error: 'QUOTA_EXCEEDED',
111	            message: err.message,
112	            ruleKey: err.ruleKey,
113	            limit: err.limit,
114	            current: err.current,
115	            retryAfter: err.retryAfter,
116	          });
117	        }
118	        if (err instanceof CooldownError) {
119	          return reply.status(429).send({
120	            error: 'COOLDOWN_ACTIVE',
121	            message: err.message,
122	            retryAfterSeconds: err.retryAfter,
123	          });
124	        }
125	        throw err;
126	      }
127	    };
128	  });
129	}
130	
131	export default fp(rulesEnginePlugin, {
132	  name: 'rules-engine',
133	  dependencies: ['database'],
134	  fastify: '5.x',
135	});
