1	import { FastifyInstance, FastifyRequest } from 'fastify';
2	import fp from 'fastify-plugin';
3	import { auditLogs } from '@studioops/db/schema';
4	
5	declare module 'fastify' {
6	  interface FastifyRequest {
7	    auditContext?: {
8	      resourceType: string;
9	      resourceId?: string;
10	      action?: string;
11	      beforeState?: unknown;
12	      afterState?: unknown;
13	    };
14	  }
15	}
16	
17	async function auditLogPlugin(fastify: FastifyInstance) {
18	  fastify.addHook('onResponse', async (request, reply) => {
19	    // Only log requests to protected API routes (skip health, static, etc.)
20	    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
21	      return;
22	    }
23	
24	    const auditCtx = request.auditContext;
25	    const resourceType = auditCtx?.resourceType || inferResourceType(request.url);
26	    const action = auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`;
27	
28	    try {
29	      await fastify.db.insert(auditLogs).values({
30	        actorId: request.user?.sub || null,
31	        action,
32	        resourceType,
33	        resourceId: auditCtx?.resourceId || null,
34	        beforeState: auditCtx?.beforeState || null,
35	        afterState: auditCtx?.afterState || null,
36	        ipAddress: request.ip,
37	        userAgent: request.headers['user-agent'] || null,
38	      });
39	    } catch (err) {
40	      // Fire-and-forget: never block the response
41	      request.log.error({ err }, 'Failed to write audit log entry');
42	    }
43	  });
44	}
45	
46	function inferResourceType(url: string): string {
47	  const segments = url.replace('/api/v1/', '').split('/');
48	  return segments[0] || 'unknown';
49	}
50	
51	export default fp(auditLogPlugin, {
52	  name: 'audit-log',
53	  dependencies: ['database'],
54	  fastify: '5.x',
55	});
