1	import ffmpeg from 'fluent-ffmpeg';
2	import { join, dirname } from 'node:path';
3	import { mkdir } from 'node:fs/promises';
4	import { MEDIA } from '@studioops/shared';
5	
6	export interface VideoProcessingResult {
7	  processedPath: string;
8	  previewPath: string;
9	  width: number;
10	  height: number;
11	  durationSeconds: number;
12	}
13	
14	export async function processVideo(
15	  inputPath: string,
16	  outputDir: string,
17	  fileId: string,
18	): Promise<VideoProcessingResult> {
19	  const processedPath = join(outputDir, 'processed', `${fileId}.mp4`);
20	  const previewPath = join(outputDir, 'previews', `${fileId}.jpg`);
21	
22	  await mkdir(dirname(processedPath), { recursive: true });
23	  await mkdir(dirname(previewPath), { recursive: true });
24	
25	  // Get input metadata
26	  const metadata = await new Promise<ffmpeg.FfprobeData>((resolve, reject) => {
27	    ffmpeg.ffprobe(inputPath, (err, data) => {
28	      if (err) reject(err);
29	      else resolve(data);
30	    });
31	  });
32	
33	  const videoStream = metadata.streams.find(s => s.codec_type === 'video');
34	  const inputHeight = videoStream?.height ?? 0;
35	  const inputWidth = videoStream?.width ?? 0;
36	  const duration = metadata.format.duration ?? 0;
37	
38	  // Determine if downscale is needed (cap at 1080p)
39	  const needsDownscale = inputHeight > MEDIA.VIDEO_MAX_HEIGHT;
40	  const scaleFilter = needsDownscale
41	    ? `-vf scale=-2:${MEDIA.VIDEO_MAX_HEIGHT}`
42	    : '';
43	
44	  // Transcode to H.264 at 1080p max
45	  await new Promise<void>((resolve, reject) => {
46	    let cmd = ffmpeg(inputPath)
47	      .videoCodec('libx264')
48	      .audioCodec('aac')
49	      .outputOptions(['-preset', 'fast', '-crf', '23', '-movflags', '+faststart']);
50	
51	    if (needsDownscale) {
52	      cmd = cmd.videoFilter(`scale=-2:${MEDIA.VIDEO_MAX_HEIGHT}`);
53	    }
54	
55	    cmd.output(processedPath)
56	      .on('end', () => resolve())
57	      .on('error', (err) => reject(err))
58	      .run();
59	  });
60	
61	  // Extract poster frame (at 1 second or 10% of duration)
62	  const seekTime = Math.min(1, duration * 0.1);
63	  await new Promise<void>((resolve, reject) => {
64	    ffmpeg(inputPath)
65	      .seekInput(seekTime)
66	      .frames(1)
67	      .output(previewPath)
68	      .on('end', () => resolve())
69	      .on('error', (err) => reject(err))
70	      .run();
71	  });
72	
73	  // Get output dimensions
74	  const outputMeta = await new Promise<ffmpeg.FfprobeData>((resolve, reject) => {
75	    ffmpeg.ffprobe(processedPath, (err, data) => {
76	      if (err) reject(err);
77	      else resolve(data);
78	    });
79	  });
80	
81	  const outputVideo = outputMeta.streams.find(s => s.codec_type === 'video');
82	
83	  return {
84	    processedPath,
85	    previewPath,
86	    width: outputVideo?.width ?? inputWidth,
87	    height: outputVideo?.height ?? Math.min(inputHeight, MEDIA.VIDEO_MAX_HEIGHT),
88	    durationSeconds: Math.round(duration),
89	  };
90	}
