1	-- Prevents UPDATE and DELETE on audit_logs to enforce immutability
2	CREATE OR REPLACE FUNCTION prevent_audit_log_mutation()
3	RETURNS TRIGGER AS $$
4	BEGIN
5	  RAISE EXCEPTION 'audit_logs table is immutable: % operations are forbidden', TG_OP;
6	  RETURN NULL;
7	END;
8	$$ LANGUAGE plpgsql;
9	
10	CREATE TRIGGER audit_logs_no_update
11	  BEFORE UPDATE ON audit_logs
12	  FOR EACH ROW EXECUTE FUNCTION prevent_audit_log_mutation();
13	
14	CREATE TRIGGER audit_logs_no_delete
15	  BEFORE DELETE ON audit_logs
16	  FOR EACH ROW EXECUTE FUNCTION prevent_audit_log_mutation();
