37	  }, async (request, reply) => {
38	    const parseResult = importBatchSchema.safeParse(request.body);
39	    if (!parseResult.success) {
40	      return reply.status(400).send({
41	        error: 'VALIDATION_ERROR',
42	        message: 'Validation failed',
43	        details: parseResult.error.issues.map(i => i.message),
44	      });
45	    }
46	
47	    const { orgId, offerings: rawOfferings } = parseResult.data;
48	
49	    // Verify merchant is in org
50	    if (request.authContext?.orgScope && !request.authContext.orgScope.includes(orgId)) {
51	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'You are not a member of this organization' });
52	    }
53	
54	    // Load existing offerings for dedup comparison
55	    const existingList = await offeringRepo.list({ page: 1, limit: 500, orgId, role: 'administrator' as Role });
56	    const existingTargets: CleansingTarget[] = existingList.data.map(o => ({
57	      id: o.id, title: o.title, priceCents: o.basePriceCents,
58	      durationMinutes: o.durationMinutes, tags: [], orgId: o.orgId,
59	    }));
60	    const medianPrice = existingTargets.length > 0
61	      ? existingTargets.map(t => t.priceCents).sort((a, b) => a - b)[Math.floor(existingTargets.length / 2)]
