69	      const priceCents = currencyResult.cents;
70	
71	      // 2. Normalize duration → minutes
72	      const durationMinutes = Math.round(normalizeDuration(raw.duration, raw.durationUnit));
73	
74	      // 3. Create the offering
75	      const offering = await offeringRepo.create({
76	        orgId,
77	        merchantId: request.user.sub,
78	        title: raw.title,
79	        description: raw.description,
80	        basePriceCents: priceCents,
81	        durationMinutes,
82	        visibility: raw.visibility,
83	      });
84	
85	      // 4. Run auto-cleansing (outliers, missing fields, duplicates)
86	      const target: CleansingTarget = {
87	        id: offering.id, title: offering.title, priceCents, durationMinutes,
88	        tags: raw.tags, orgId,
89	        rawCurrency: raw.currency !== 'USD' ? raw.currency : undefined,
90	        rawDuration: raw.durationUnit !== 'minutes' ? { value: raw.duration, unit: raw.durationUnit } : undefined,
91	      };
92	
93	      const cleansed = autoCleanseRecord(target, existingTargets, medianPrice);
94	
95	      // 5. Persist flags
96	      if (currencyResult.flagged) {
97	        cleansed.flags.push({ field: 'currency', issue: 'UNKNOWN_CURRENCY', detail: { currency: raw.currency } });
98	      }
99	
100	      for (const flag of cleansed.flags) {
101	        await cleansingRepo.createFlag({ recordType: 'offering', recordId: offering.id, field: flag.field, issue: flag.issue, detail: flag.detail });
102	      }
103	
104	      // 6. Persist duplicate candidates
105	      for (const dup of cleansed.duplicateCandidates) {
106	        await cleansingRepo.createCandidate({
107	          recordType: 'offering', recordAId: offering.id, recordBId: dup.existingId,
108	          similarityScore: dup.score, featureScores: dup.featureScores,
109	        });
110	      }
111	
112	      // Add to existing targets for subsequent dedup checks within the batch
113	      existingTargets.push(target);
114	
115	      results.push({
116	        title: raw.title,
117	        id: offering.id,
118	        status: 'imported',
119	        flags: cleansed.flags,
120	        duplicates: cleansed.duplicateCandidates,
121	      });
122	    }
123	
124	    request.auditContext = {
125	      resourceType: 'import',
126	      afterState: { count: results.length, orgId },
127	    };
128	
129	    return reply.status(201).send({
130	      imported: results.length,
131	      results,
132	    });
133	  });
134	}
