3	// --- Currency normalization ---
4	
5	/** Simplified exchange rates to USD (for offline use). Real system would use a configurable table. */
6	const EXCHANGE_RATES: Record<string, number> = {
7	  USD: 1,
8	  EUR: 1.08,
9	  GBP: 1.27,
10	  JPY: 0.0067,
11	  CAD: 0.74,
12	  AUD: 0.65,
13	  CHF: 1.13,
14	};
15	
16	export interface CurrencyNormalizationResult {
17	  cents: number;
18	  originalCurrency: string;
19	  flagged: boolean;
20	  flagReason?: string;
21	}
22	
23	export function normalizeCurrency(amount: number, currency: string): CurrencyNormalizationResult {
24	  const upper = currency.toUpperCase();
25	  const rate = EXCHANGE_RATES[upper];
26	
27	  if (!rate) {
28	    return {
29	      cents: Math.round(amount * 100),
30	      originalCurrency: upper,
31	      flagged: true,
32	      flagReason: `Unknown currency: ${upper}`,
33	    };
34	  }
35	
36	  const usdAmount = amount * rate;
37	  return {
38	    cents: Math.round(usdAmount * 100),
39	    originalCurrency: upper,
40	    flagged: false,
41	  };
42	}
43	
44	// --- Duration normalization ---
45	
46	export function normalizeDuration(value: number, unit: 'seconds' | 'minutes' | 'hours'): number {
47	  switch (unit) {
48	    case 'seconds': return value / 60;
49	    case 'minutes': return value;
50	    case 'hours': return value * 60;
51	  }
52	}
53	
54	// --- Dimension normalization ---
55	
56	export function cmToInches(cm: number): number {
57	  return cm / 2.54;
58	}
59	
60	export function mmToInches(mm: number): number {
61	  return mm / 25.4;
62	}
63	
64	export function pixelsToInches(pixels: number, dpi: number = DPI_STANDARD): number {
65	  return pixels / dpi;
66	}
67	
68	export function paperSizeToInches(sizeName: string): { widthInches: number; heightInches: number } | null {
69	  return PAPER_SIZES[sizeName] ?? null;
70	}
71	
72	// --- Outlier detection ---
73	
74	export interface OutlierResult {
75	  isOutlier: boolean;
76	  value: number;
77	  median: number;
78	  ratio: number;
79	}
80	
81	export function detectOutlier(value: number, median: number, threshold: number = 10): OutlierResult {
82	  if (median === 0) {
83	    return { isOutlier: false, value, median, ratio: 0 };
84	  }
85	
86	  const ratio = value / median;
87	  const isOutlier = ratio > threshold || ratio < (1 / threshold);
88	
89	  return { isOutlier, value, median, ratio };
90	}
