1	import { DEDUP } from '@studioops/shared';
2	
3	// --- Levenshtein distance ---
4	
5	export function levenshteinDistance(a: string, b: string): number {
6	  const la = a.length;
7	  const lb = b.length;
8	  const matrix: number[][] = Array.from({ length: la + 1 }, (_, i) =>
9	    Array.from({ length: lb + 1 }, (_, j) => (i === 0 ? j : j === 0 ? i : 0)),
10	  );
11	
12	  for (let i = 1; i <= la; i++) {
13	    for (let j = 1; j <= lb; j++) {
14	      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
15	      matrix[i][j] = Math.min(
16	        matrix[i - 1][j] + 1,
17	        matrix[i][j - 1] + 1,
18	        matrix[i - 1][j - 1] + cost,
19	      );
20	    }
21	  }
22	
23	  return matrix[la][lb];
24	}
25	
26	export function levenshteinRatio(a: string, b: string): number {
27	  if (a.length === 0 && b.length === 0) return 1;
28	  const maxLen = Math.max(a.length, b.length);
29	  if (maxLen === 0) return 1;
30	  return 1 - levenshteinDistance(a.toLowerCase(), b.toLowerCase()) / maxLen;
31	}
32	
33	// --- Numeric distance ---
34	
35	export function numericSimilarity(a: number, b: number): number {
36	  if (a === 0 && b === 0) return 1;
37	  const maxVal = Math.max(Math.abs(a), Math.abs(b));
38	  if (maxVal === 0) return 1;
39	  return 1 - Math.abs(a - b) / maxVal;
40	}
41	
42	// --- Jaccard index for tag sets ---
43	
44	export function jaccardIndex(a: string[], b: string[]): number {
45	  const setA = new Set(a.map((s) => s.toLowerCase()));
46	  const setB = new Set(b.map((s) => s.toLowerCase()));
47	
48	  if (setA.size === 0 && setB.size === 0) return 1;
49	
50	  let intersection = 0;
51	  for (const item of setA) {
52	    if (setB.has(item)) intersection++;
53	  }
54	
55	  const union = setA.size + setB.size - intersection;
56	  if (union === 0) return 1;
57	
58	  return intersection / union;
59	}
60	
61	// --- Weighted composite similarity ---
62	
63	export interface SimilarityInput {
64	  titleA: string;
65	  titleB: string;
66	  priceA: number;
67	  priceB: number;
68	  durationA: number;
69	  durationB: number;
70	  tagsA: string[];
71	  tagsB: string[];
72	}
73	
74	export interface SimilarityResult {
75	  compositeScore: number;
76	  featureScores: {
77	    title: number;
78	    price: number;
79	    duration: number;
80	    tags: number;
81	  };
82	  isDuplicate: boolean;
83	}
84	
85	export function computeSimilarity(input: SimilarityInput): SimilarityResult {
86	  const titleScore = levenshteinRatio(input.titleA, input.titleB);
87	  const priceScore = numericSimilarity(input.priceA, input.priceB);
88	  const durationScore = numericSimilarity(input.durationA, input.durationB);
89	  const tagsScore = jaccardIndex(input.tagsA, input.tagsB);
90	
91	  const compositeScore =
92	    titleScore * DEDUP.WEIGHTS.TITLE +
93	    priceScore * DEDUP.WEIGHTS.PRICE +
94	    durationScore * DEDUP.WEIGHTS.DURATION +
95	    tagsScore * DEDUP.WEIGHTS.TAGS;
96	
97	  return {
98	    compositeScore,
99	    featureScores: {
100	      title: titleScore,
101	      price: priceScore,
102	      duration: durationScore,
103	      tags: tagsScore,
104	    },
105	    isDuplicate: compositeScore >= DEDUP.SIMILARITY_THRESHOLD,
106	  };
107	}
