127	export class PortfolioComponent implements OnInit {
128	  private http = inject(HttpClient);
129	  items = signal<any[]>([]);
130	  loading = signal(true);
131	  uploadStatus = signal<string>('');
132	  uploadMessage = signal('');
133	  categories = signal<any[]>([]);
134	  newCategoryName = '';
135	  editingTagsItemId = signal<string | null>(null);
136	  tagInput = '';
137	  uploadCategoryId = '';
138	
139	  private notifications = inject(NotificationService);
140	
141	  ngOnInit(): void { this.load(); this.loadCategories(); }
142	
143	  async load(): Promise<void> {
144	    try {
145	      const res = await firstValueFrom(this.http.get<any>('/api/v1/portfolio'));
146	      this.items.set(res.data);
147	    } finally { this.loading.set(false); }
148	  }
149	
150	  async loadCategories(): Promise<void> {
151	    try {
152	      const res = await firstValueFrom(this.http.get<any>('/api/v1/portfolio/categories'));
153	      this.categories.set(res.data);
154	    } catch { /* ignore */ }
155	  }
156	
157	  async createCategory(): Promise<void> {
158	    if (!this.newCategoryName.trim()) return;
159	    try {
160	      await firstValueFrom(this.http.post('/api/v1/portfolio/categories', { name: this.newCategoryName.trim() }));
161	      this.newCategoryName = '';
162	      this.loadCategories();
163	      this.notifications.success('Category created');
164	    } catch { this.notifications.error('Failed to create category'); }
165	  }
166	
167	  async deleteCategory(id: string): Promise<void> {
168	    try {
169	      await firstValueFrom(this.http.delete(`/api/v1/portfolio/categories/${id}`));
170	      this.categories.update(list => list.filter(c => c.id !== id));
171	    } catch { this.notifications.error('Failed to delete category'); }
172	  }
173	
174	  editTags(itemId: string): void {
175	    const item = this.items().find(i => i.id === itemId);
176	    this.tagInput = item?.tags?.map((t: any) => t.name).join(', ') || '';
177	    this.editingTagsItemId.set(itemId);
178	  }
179	
180	  async saveTags(): Promise<void> {
181	    const itemId = this.editingTagsItemId();
182	    if (!itemId) return;
183	    const tagNames = this.tagInput.split(',').map(t => t.trim()).filter(Boolean);
184	    try {
185	      await firstValueFrom(this.http.patch(`/api/v1/portfolio/${itemId}/tags`, { tagNames }));
186	      this.editingTagsItemId.set(null);
187	      this.load();
188	      this.notifications.success('Tags updated');
189	    } catch { this.notifications.error('Failed to update tags'); }
190	  }
191	
192	  async assignCategory(itemId: string, event: Event): Promise<void> {
193	    const categoryId = (event.target as HTMLSelectElement).value || null;
194	    try {
195	      await firstValueFrom(this.http.patch(`/api/v1/portfolio/${itemId}/category`, { categoryId }));
196	      this.items.update(list => list.map(i => i.id === itemId ? { ...i, categoryId } : i));
197	      this.notifications.success('Category updated');
198	    } catch { this.notifications.error('Failed to assign category'); }
199	  }
200	
201	  async deleteItem(itemId: string): Promise<void> {
202	    try {
203	      await firstValueFrom(this.http.delete(`/api/v1/portfolio/${itemId}`));
204	      this.items.update(list => list.filter(i => i.id !== itemId));
205	      this.notifications.success('Item deleted');
206	    } catch { this.notifications.error('Failed to delete item'); }
207	  }
208	
209	  async onFileSelected(event: Event): Promise<void> {
210	    const input = event.target as HTMLInputElement;
211	    if (!input.files?.length) return;
212	
213	    const file = input.files[0];
214	    const formData = new FormData();
215	    formData.append('file', file);
216	    formData.append('title', file.name.replace(/\.[^.]+$/, ''));
217	    if (this.uploadCategoryId) {
218	      formData.append('categoryId', this.uploadCategoryId);
219	    }
220	
221	    this.uploadStatus.set('uploading');
222	    this.uploadMessage.set(`Uploading ${file.name}...`);
223	
224	    try {
225	      const res = await firstValueFrom(this.http.post<any>('/api/v1/portfolio/upload', formData));
226	      this.uploadStatus.set('success');
227	      this.uploadMessage.set(`Uploaded "${res.title}" — status: ${res.status}`);
228	      this.load();
229	    } catch (err: any) {
230	      this.uploadStatus.set('error');
231	      this.uploadMessage.set(err.error?.message || 'Upload failed');
232	    }
233	
234	    input.value = '';
235	  }
236	}
