1	import { normalizeCurrency, normalizeDuration, detectOutlier } from '../domain/normalizers';
2	import { computeSimilarity } from '../domain/similarity';
3	import { DEDUP } from '@studioops/shared';
4	
5	export interface CleansingTarget {
6	  id: string;
7	  title: string;
8	  priceCents: number;
9	  durationMinutes: number;
10	  tags: string[];
11	  orgId: string;
12	  /** Optional: raw currency before normalization (for flagging unknown currencies) */
13	  rawCurrency?: string;
14	  /** Optional: raw duration value + unit before normalization */
15	  rawDuration?: { value: number; unit: 'seconds' | 'minutes' | 'hours' };
16	}
17	
18	export interface CleansingResult {
19	  flags: Array<{ field: string; issue: string; detail?: unknown }>;
20	  duplicateCandidates: Array<{ existingId: string; score: number; featureScores: unknown }>;
21	}
22	
23	/**
24	 * Run automatic cleansing on a new/updated record:
25	 * 1. Detect outliers (price vs category median)
26	 * 2. Flag missing required fields
27	 * 3. Compare against existing records for duplicates
28	 */
29	export function autoCleanseRecord(
30	  record: CleansingTarget,
31	  existingRecords: CleansingTarget[],
32	  categoryMedianPrice: number,
33	): CleansingResult {
34	  const flags: CleansingResult['flags'] = [];
35	  const duplicateCandidates: CleansingResult['duplicateCandidates'] = [];
36	
37	  // Normalize currency if raw value provided
38	  if (record.rawCurrency && record.rawCurrency !== 'USD') {
39	    const normalized = normalizeCurrency(record.priceCents / 100, record.rawCurrency);
40	    if (normalized.flagged) {
41	      flags.push({ field: 'currency', issue: 'UNKNOWN_CURRENCY', detail: { currency: record.rawCurrency, reason: normalized.flagReason } });
42	    }
43	    record.priceCents = normalized.cents;
44	  }
45	
46	  // Normalize duration if raw value provided
47	  if (record.rawDuration && record.rawDuration.unit !== 'minutes') {
48	    record.durationMinutes = normalizeDuration(record.rawDuration.value, record.rawDuration.unit);
49	  }
50	
51	  // Outlier detection on price
52	  if (categoryMedianPrice > 0) {
53	    const outlier = detectOutlier(record.priceCents, categoryMedianPrice);
54	    if (outlier.isOutlier) {
55	      flags.push({ field: 'price', issue: 'OUTLIER', detail: { value: record.priceCents, median: categoryMedianPrice, ratio: outlier.ratio } });
56	    }
57	  }
58	
59	  // Missing field checks
60	  if (!record.title || record.title.trim().length === 0) {
61	    flags.push({ field: 'title', issue: 'MISSING' });
62	  }
63	  if (record.priceCents < 0) {
64	    flags.push({ field: 'price', issue: 'INVALID', detail: { value: record.priceCents } });
65	  }
66	  if (record.durationMinutes <= 0) {
67	    flags.push({ field: 'duration', issue: 'INVALID', detail: { value: record.durationMinutes } });
68	  }
69	
70	  // Dedup: compare against existing records in same org
71	  for (const existing of existingRecords) {
72	    if (existing.id === record.id) continue;
73	    if (existing.orgId !== record.orgId) continue;
74	
75	    const similarity = computeSimilarity({
76	      titleA: record.title,
77	      titleB: existing.title,
78	      priceA: record.priceCents,
79	      priceB: existing.priceCents,
80	      durationA: record.durationMinutes,
81	      durationB: existing.durationMinutes,
82	      tagsA: record.tags,
83	      tagsB: existing.tags,
84	    });
85	
86	    if (similarity.isDuplicate) {
87	      duplicateCandidates.push({
88	        existingId: existing.id,
89	        score: similarity.compositeScore,
90	        featureScores: similarity.featureScores,
91	      });
92	    }
93	  }
94	
95	  return { flags, duplicateCandidates };
96	}
