2	import { join, dirname } from 'node:path';
3	import { mkdir } from 'node:fs/promises';
4	import { MEDIA } from '@studioops/shared';
5	
6	export interface ImageProcessingResult {
7	  processedPath: string;
8	  previewPath: string;
9	  width: number;
10	  height: number;
11	}
12	
13	export async function processImage(
14	  inputPath: string,
15	  outputDir: string,
16	  fileId: string,
17	): Promise<ImageProcessingResult> {
18	  const processedPath = join(outputDir, 'processed', `${fileId}.jpg`);
19	  const previewPath = join(outputDir, 'previews', `${fileId}.jpg`);
20	
21	  await mkdir(dirname(processedPath), { recursive: true });
22	  await mkdir(dirname(previewPath), { recursive: true });
23	
24	  // Process main image: resize to max 3000px long edge, JPEG quality 80
25	  const metadata = await sharp(inputPath).metadata();
26	  const { width: origW = 0, height: origH = 0 } = metadata;
27	
28	  let resizeOpts: sharp.ResizeOptions | undefined;
29	  const longEdge = Math.max(origW, origH);
30	  if (longEdge > MEDIA.PHOTO_MAX_LONG_EDGE) {
31	    if (origW >= origH) {
32	      resizeOpts = { width: MEDIA.PHOTO_MAX_LONG_EDGE, withoutEnlargement: true };
33	    } else {
34	      resizeOpts = { height: MEDIA.PHOTO_MAX_LONG_EDGE, withoutEnlargement: true };
35	    }
36	  }
37	
38	  const processed = sharp(inputPath);
39	  if (resizeOpts) processed.resize(resizeOpts);
40	  const processedInfo = await processed
41	    .jpeg({ quality: MEDIA.PHOTO_JPEG_QUALITY })
42	    .toFile(processedPath);
43	
44	  // Generate preview thumbnail: 400px
45	  await sharp(inputPath)
46	    .resize({ width: MEDIA.PHOTO_PREVIEW_SIZE, withoutEnlargement: true })
47	    .jpeg({ quality: 70 })
48	    .toFile(previewPath);
49	
50	  return {
51	    processedPath,
52	    previewPath,
53	    width: processedInfo.width,
54	    height: processedInfo.height,
55	  };
56	}
