8	const MIME_MAP: Record<string, string> = {
9	  '.jpg': 'image/jpeg',
10	  '.jpeg': 'image/jpeg',
11	  '.png': 'image/png',
12	  '.tiff': 'image/tiff',
13	  '.mp4': 'video/mp4',
14	  '.mov': 'video/quicktime',
15	};
