17	export default async function mediaRoutes(fastify: FastifyInstance) {
18	  const storageRoot = resolve(process.env.STORAGE_ROOT || './data/media');
19	
20	  // GET /media/* — serve processed/preview media files with ownership/org authorization
21	  fastify.get('/*', {
22	    preHandler: [fastify.authenticate],
23	  }, async (request: FastifyRequest, reply: FastifyReply) => {
24	    const params = request.params as { '*': string };
25	    const relativePath = normalize(params['*']);
26	
27	    // Prevent directory traversal
28	    if (relativePath.includes('..') || relativePath.startsWith('/')) {
29	      return reply.status(400).send({ error: 'BAD_REQUEST', message: 'Invalid path' });
30	    }
31	
32	    // Only serve from processed/ and previews/ subdirectories
33	    const pathParts = relativePath.split('/');
34	    if (pathParts.length < 3 || !['processed', 'previews'].includes(pathParts[1])) {
35	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'Access to this path is not allowed' });
36	    }
37	
38	    // Look up the portfolio item that owns this media path
39	    const [item] = await fastify.db
40	      .select({
41	        id: portfolioItems.id,
42	        merchantId: portfolioItems.merchantId,
43	        originalOrgId: portfolioItems.originalOrgId,
44	      })
45	      .from(portfolioItems)
46	      .where(or(
47	        eq(portfolioItems.processedPath, relativePath),
48	        eq(portfolioItems.previewPath, relativePath),
49	      ))
50	      .limit(1);
51	
52	    if (!item) {
53	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Media file not found' });
54	    }
55	
56	    // Enforce same authorization as GET /portfolio/:id
57	    if (request.user.role === 'administrator') {
58	      // Admin sees all
59	    } else if (request.user.role === 'merchant') {
60	      if (item.merchantId !== request.user.sub) {
61	        return reply.status(404).send({ error: 'NOT_FOUND', message: 'Media file not found' });
62	      }
63	    } else {
64	      const orgScope = request.authContext?.orgScope ?? [];
65	      if (!orgScope.includes(item.originalOrgId)) {
66	        return reply.status(404).send({ error: 'NOT_FOUND', message: 'Media file not found' });
67	      }
68	    }
69	
70	    const absolutePath = join(storageRoot, relativePath);
71	
72	    // Ensure resolved path is still within storage root
73	    if (!absolutePath.startsWith(storageRoot)) {
74	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'Access denied' });
75	    }
76	
77	    if (!existsSync(absolutePath)) {
78	      return reply.status(404).send({ error: 'NOT_FOUND', message: 'Media file not found' });
79	    }
80	
81	    const fileStat = await stat(absolutePath);
82	    const ext = '.' + relativePath.split('.').pop()?.toLowerCase();
83	    const contentType = MIME_MAP[ext] || 'application/octet-stream';
84	
85	    reply
86	      .header('Content-Type', contentType)
87	      .header('Content-Length', fileStat.size)
88	      .header('Cache-Control', 'private, max-age=3600');
89	
90	    return reply.send(createReadStream(absolutePath));
91	  });
92	}
