1	import { Component, inject, signal, OnInit } from '@angular/core';
2	import { HttpClient } from '@angular/common/http';
3	import { FormsModule } from '@angular/forms';
4	import { DatePipe } from '@angular/common';
5	import { firstValueFrom } from 'rxjs';
6	import { NotificationService } from '../../core/services/notification.service';
7	
8	@Component({
9	  selector: 'app-admin',
10	  standalone: true,
11	  imports: [FormsModule, DatePipe],
12	  template: `
13	    <div class="space-y-6">
14	      <h2 class="text-2xl font-semibold tracking-tight">Administration</h2>
15	
16	      <!-- Tabs -->
17	      <div class="flex gap-1 border-b">
18	        @for (tab of tabs; track tab) {
19	          <button
20	            (click)="activeTab.set(tab)"
21	            class="px-4 py-2 text-sm font-medium transition-colors"
22	            [class]="activeTab() === tab ? 'border-b-2 border-[hsl(var(--primary))] text-[hsl(var(--primary))]' : 'text-[hsl(var(--muted-foreground))] hover:text-[hsl(var(--foreground))]'">
23	            {{ tab }}
24	          </button>
25	        }
26	      </div>
27	
28	      <!-- Roles Tab -->
29	      @if (activeTab() === 'Roles') {
30	        <div class="rounded-lg border bg-[hsl(var(--card))] p-4">
31	          @if (roles().length > 0) {
32	            <div class="overflow-x-auto">
33	              <table class="w-full text-sm">
34	                <thead><tr class="border-b">
35	                  <th class="py-2 text-left font-medium">Role</th>
36	                  <th class="py-2 text-left font-medium">Permissions</th>
37	                </tr></thead>
38	                <tbody>
39	                  @for (role of roles(); track role.role) {
40	                    <tr class="border-b last:border-0">
41	                      <td class="py-2 capitalize font-medium">{{ role.role }}</td>
42	                      <td class="py-2"><div class="flex flex-wrap gap-1">
43	                        @for (p of role.permissions; track p) {
44	                          <span class="rounded bg-[hsl(var(--accent))] px-1.5 py-0.5 text-xs">{{ p }}</span>
45	                        }
46	                      </div></td>
47	                    </tr>
48	                  }
49	                </tbody>
50	              </table>
51	            </div>
52	          } @else {
53	            <p class="text-sm text-[hsl(var(--muted-foreground))]">Loading roles...</p>
54	          }
55	        </div>
56	      }
57	
58	      <!-- Rules Tab -->
59	      @if (activeTab() === 'Rules') {
60	        <div class="space-y-3">
61	          @for (rule of rules(); track rule.id) {
62	            <div class="rounded-lg border bg-[hsl(var(--card))] p-4">
63	              <div class="flex items-center justify-between">
64	                <div>
65	                  <span class="font-medium">{{ rule.ruleKey }}</span>
66	                  <span class="ml-2 text-xs text-[hsl(var(--muted-foreground))]">v{{ rule.version }}</span>
67	                </div>
68	                <span class="rounded-full px-2 py-0.5 text-xs"
69	                  [class]="rule.status === 'active' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-600'">
70	                  {{ rule.status }}
71	                </span>
72	              </div>
73	              <div class="mt-2 text-xs text-[hsl(var(--muted-foreground))]">
74	                Limit: {{ rule.config?.limit }} / {{ rule.config?.window }} · Canary: {{ rule.canaryPercent }}%
75	              </div>
76	            </div>
77	          }
78	        </div>
79	      }
80	
81	      <!-- Audit Tab -->
82	      @if (activeTab() === 'Audit') {
83	        <div class="rounded-lg border bg-[hsl(var(--card))]">
84	          <div class="max-h-96 overflow-auto">
85	            <table class="w-full text-sm">
86	              <thead class="sticky top-0 bg-[hsl(var(--card))]"><tr class="border-b">
87	                <th class="px-3 py-2 text-left font-medium">Time</th>
88	                <th class="px-3 py-2 text-left font-medium">Action</th>
89	                <th class="px-3 py-2 text-left font-medium">Resource</th>
90	                <th class="px-3 py-2 text-left font-medium">IP</th>
91	              </tr></thead>
92	              <tbody>
93	                @for (log of auditLogs(); track log.id) {
94	                  <tr class="border-b last:border-0 hover:bg-[hsl(var(--accent))]">
95	                    <td class="px-3 py-2 text-xs">{{ log.createdAt | date:'MM/dd HH:mm:ss' }}</td>
96	                    <td class="px-3 py-2 text-xs font-mono">{{ log.action }}</td>
97	                    <td class="px-3 py-2 text-xs">{{ log.resourceType }}</td>
98	                    <td class="px-3 py-2 text-xs">{{ log.ipAddress }}</td>
99	                  </tr>
100	                }
101	              </tbody>
102	            </table>
103	          </div>
104	        </div>
105	      }
106	
107	      <!-- Config Tab -->
108	      @if (activeTab() === 'Config') {
109	        <div class="space-y-3">
110	          @for (entry of configEntries(); track entry.key) {
111	            <div class="flex items-center justify-between rounded-lg border bg-[hsl(var(--card))] p-4">
112	              <div>
113	                <span class="font-medium font-mono text-sm">{{ entry.key }}</span>
114	                <div class="mt-1 text-sm text-[hsl(var(--muted-foreground))]">{{ entry.displayValue }}</div>
115	              </div>
116	              <div class="flex items-center gap-2">
117	                @if (entry.isEncrypted) {
118	                  <button (click)="revealConfig(entry.key)" class="rounded border px-2 py-1 text-xs hover:bg-[hsl(var(--accent))]">Reveal</button>
119	                  <span class="rounded-full bg-yellow-100 px-2 py-0.5 text-xs text-yellow-800">Encrypted</span>
120	                }
121	              </div>
122	            </div>
123	          }
124	          @if (configEntries().length === 0) {
125	            <p class="text-sm text-[hsl(var(--muted-foreground))]">No config entries</p>
126	          }
127	        </div>
128	      }
129	
130	      <!-- Sessions Tab -->
131	      @if (activeTab() === 'Sessions') {
132	        <div class="space-y-2">
133	          @for (session of sessions(); track session.id) {
134	            <div class="flex items-center justify-between rounded-lg border bg-[hsl(var(--card))] p-3">
135	              <div class="text-sm">
136	                <span class="font-mono text-xs">{{ session.tokenJti }}</span>
137	                <span class="ml-2 text-[hsl(var(--muted-foreground))]">{{ session.lastActivityAt | date:'MM/dd HH:mm' }}</span>
138	              </div>
139	              <button (click)="revokeSession(session.id)"
140	                class="rounded border border-red-200 px-2 py-1 text-xs text-red-600 hover:bg-red-50">Revoke</button>
141	            </div>
142	          }
143	        </div>
144	      }
145	    </div>
146	  `,
147	})
148	export class AdminComponent implements OnInit {
149	  private http = inject(HttpClient);
150	  private notifications = inject(NotificationService);
151	
152	  tabs = ['Roles', 'Rules', 'Audit', 'Config', 'Sessions'];
153	  activeTab = signal('Roles');
154	
155	  roles = signal<any[]>([]);
156	  rules = signal<any[]>([]);
157	  auditLogs = signal<any[]>([]);
158	  configEntries = signal<any[]>([]);
159	  sessions = signal<any[]>([]);
160	
161	  ngOnInit(): void { this.loadAll(); }
162	
163	  async loadAll(): Promise<void> {
164	    const [rolesRes, rulesRes, auditRes, configRes, sessRes] = await Promise.allSettled([
165	      firstValueFrom(this.http.get<any>('/api/v1/admin/roles')),
166	      firstValueFrom(this.http.get<any>('/api/v1/admin/rules')),
167	      firstValueFrom(this.http.get<any>('/api/v1/admin/audit?limit=50')),
168	      firstValueFrom(this.http.get<any>('/api/v1/admin/config')),
169	      firstValueFrom(this.http.get<any>('/api/v1/admin/sessions')),
170	    ]);
171	
172	    if (rolesRes.status === 'fulfilled') this.roles.set(rolesRes.value.data);
173	    if (rulesRes.status === 'fulfilled') this.rules.set(rulesRes.value.data);
174	    if (auditRes.status === 'fulfilled') this.auditLogs.set(auditRes.value.data);
175	    if (configRes.status === 'fulfilled') this.configEntries.set(configRes.value.data);
176	    if (sessRes.status === 'fulfilled') this.sessions.set(sessRes.value.data);
177	  }
178	
179	  async revokeSession(id: string): Promise<void> {
180	    try {
181	      await firstValueFrom(this.http.delete(`/api/v1/admin/sessions/${id}`));
182	      this.sessions.update(list => list.filter(s => s.id !== id));
183	      this.notifications.success('Session revoked');
184	    } catch { this.notifications.error('Failed to revoke session'); }
185	  }
186	
187	  async revealConfig(key: string): Promise<void> {
188	    const password = prompt('Enter your password to reveal this value:');
189	    if (!password) return;
190	    try {
191	      const res = await firstValueFrom(this.http.post<any>(`/api/v1/admin/config/${key}/reveal`, { password }));
192	      this.configEntries.update(list => list.map(e => e.key === key ? { ...e, displayValue: res.value } : e));
193	      this.notifications.success('Value revealed (will re-mask on reload)');
194	    } catch (err: any) {
195	      this.notifications.error(err?.error?.message || 'Reveal failed — check your password');
196	    }
197	  }
198	}
