import fp from 'fastify-plugin';
import rateLimit from '@fastify/rate-limit';
import { RATE_LIMITS } from '@studioops/shared';

const isTest = process.env.NODE_ENV === 'test';
const TEST_MULTIPLIER = isTest ? 100 : 1;

/**
 * Lightweight JWT payload extraction for rate-limit keying.
 * Decodes the payload section without cryptographic verification —
 * full verification happens later in route preHandlers.
 * This is safe because the rate-limit key only affects throttling buckets,
 * not authorization decisions.
 */
function extractTokenIdentity(request: FastifyRequest): { sub?: string; role?: string } | null {
  const auth = request.headers.authorization;
  if (!auth?.startsWith('Bearer ')) return null;
  try {
    const payload = auth.slice(7).split('.')[1];
    if (!payload) return null;
    const decoded = JSON.parse(Buffer.from(payload, 'base64url').toString());
    if (decoded.sub && typeof decoded.sub === 'string') {
      return { sub: decoded.sub, role: decoded.role };
    }
  } catch { /* malformed token — treat as guest */ }
  return null;
}

async function rateLimitPlugin(fastify: FastifyInstance) {
  await fastify.register(rateLimit, {
    max: (request) => {
      // Check request.user first (populated by auth), fallback to token decode
      const identity = request.user?.sub ? request.user : extractTokenIdentity(request);
      if (identity?.role === 'administrator') return 999999;
      if (identity?.sub) return RATE_LIMITS.AUTHENTICATED * TEST_MULTIPLIER;
      return RATE_LIMITS.GUEST * TEST_MULTIPLIER;
    },
    timeWindow: RATE_LIMITS.WINDOW_MS,
    keyGenerator: (request) => {
      const identity = request.user?.sub ? request.user : extractTokenIdentity(request);
      if (identity?.sub) return `user:${identity.sub}`;
      return `guest:${request.ip}`;
    },
    errorResponseBuilder: (_request, context) => {
      return {
        error: 'TOO_MANY_REQUESTS',
        message: 'Rate limit exceeded',
        retryAfter: Math.ceil(context.ttl / 1000),
      };
    },
  });
}

export default fp(rateLimitPlugin, {
  name: 'rate-limit',
  fastify: '5.x',
});"}

