70	    const maxSessionExpiry = new Date(session.issuedAt.getTime() + SESSION.ABSOLUTE_SESSION_LIFETIME_SECONDS * 1000);
71	    const candidateExpiry = new Date(now.getTime() + SESSION.ABSOLUTE_SESSION_LIFETIME_SECONDS * 1000);
72	    const cappedExpiry = candidateExpiry < maxSessionExpiry ? candidateExpiry : maxSessionExpiry;
73	
74	    // Update session's tokenJti and absoluteExpiresAt (capped to max boundary)
75	    await this.sessionRepo.updateSessionExpiry(session.id, jti, cappedExpiry);
76	
77	    await this.sessionRepo.createRefreshToken({
78	      sessionId: session.id,
79	      tokenHash: newRefreshTokenPair.hash,
