1	import { FastifyInstance } from 'fastify';
2	import fp from 'fastify-plugin';
3	import { sql } from 'drizzle-orm';
4	import { AUDIT } from '@studioops/shared';
5	
6	/**
7	 * Audit log retention plugin.
8	 * Runs daily to purge audit entries older than 365 days.
9	 * Uses a privileged approach: temporarily disables the immutability trigger,
10	 * deletes old rows, then re-enables the trigger.
11	 */
12	async function auditRetentionPlugin(fastify: FastifyInstance) {
13	  const PURGE_INTERVAL_MS = 24 * 60 * 60 * 1000; // 24 hours
14	  let timer: ReturnType<typeof setInterval> | null = null;
15	
16	  async function purgeOldAuditLogs(): Promise<number> {
17	    const cutoff = new Date(Date.now() - AUDIT.RETENTION_DAYS * 24 * 60 * 60 * 1000);
18	    try {
19	      // Temporarily disable the delete trigger for this operation
20	      await fastify.db.execute(sql`ALTER TABLE audit_logs DISABLE TRIGGER audit_logs_no_delete`);
21	
22	      // Delete old entries
23	      const result = await fastify.db.execute(
24	        sql`DELETE FROM audit_logs WHERE created_at < ${cutoff}`,
25	      );
26	
27	      // Re-enable the trigger
28	      await fastify.db.execute(sql`ALTER TABLE audit_logs ENABLE TRIGGER audit_logs_no_delete`);
29	
30	      const count = Array.isArray(result) ? result.length : 0;
31	      if (count > 0) {
32	        fastify.log.info({ count, cutoffDate: cutoff.toISOString() }, 'Purged old audit log entries');
33	      }
34	      return count;
35	    } catch (err) {
36	      // Re-enable trigger even on error
37	      try {
38	        await fastify.db.execute(sql`ALTER TABLE audit_logs ENABLE TRIGGER audit_logs_no_delete`);
39	      } catch { /* ignore re-enable errors */ }
40	      fastify.log.error({ err }, 'Audit log retention purge failed');
41	      return 0;
42	    }
43	  }
44	
45	  // Schedule daily purge (first run after 1 minute, then every 24 hours)
46	  fastify.addHook('onReady', () => {
47	    setTimeout(() => {
48	      purgeOldAuditLogs();
49	      timer = setInterval(purgeOldAuditLogs, PURGE_INTERVAL_MS);
50	    }, 60_000);
51	  });
52	
53	  fastify.addHook('onClose', () => {
54	    if (timer) clearInterval(timer);
55	  });
56	}
57	
58	export default fp(auditRetentionPlugin, {
59	  name: 'audit-retention',
60	  dependencies: ['database'],
61	  fastify: '5.x',
62	});
