import fp from 'fastify-plugin';
import { auditLogs } from '@studioops/db/schema';

declare module 'fastify' {
  interface FastifyRequest {
    auditContext?: {
      resourceType: string;
      resourceId?: string;
      action?: string;
      beforeState?: unknown;
      afterState?: unknown;
    };
  }
}

const READ_METHODS = new Set(['GET', 'HEAD', 'OPTIONS']);

async function auditLogPlugin(fastify: FastifyInstance) {
  // Use onSend hook (before response body is sent) so we can fail the request if audit write fails
  fastify.addHook('onSend', async (request: FastifyRequest, reply: FastifyReply, payload) => {
    // Only log requests to protected API routes (skip health, static, etc.)
    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
      return payload;
    }

    // Skip audit for failed responses (4xx/5xx) — the action didn't succeed
    if (reply.statusCode >= 400) {
      return payload;
    }

    const auditCtx = request.auditContext;
    const resourceType = auditCtx?.resourceType || inferResourceType(request.url);
    const action = auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`;

    try {
      await fastify.db.insert(auditLogs).values({
        actorId: request.user?.sub || null,
        action,
        resourceType,
        resourceId: auditCtx?.resourceId || null,
        beforeState: auditCtx?.beforeState || null,
        afterState: auditCtx?.afterState || null,
        ipAddress: request.ip,
        userAgent: request.headers['user-agent'] || null,
      });
    } catch (err) {
      request.log.error({ err }, 'Failed to write audit log entry');

      // Fail-closed for write operations: if audit can't be recorded, reject the response
      if (!READ_METHODS.has(request.method)) {
        reply.code(503);
        return JSON.stringify({
          error: 'AUDIT_FAILURE',
          message: 'Operation could not be audited. Please retry.',
        });
      }
      // For read operations, log the failure but allow the response through
    }

    return payload;
  });
}"}

