2	 * Applies audit immutability triggers to the database.
3	 * Idempotent — safe to run multiple times.
4	 * Used by both Docker entrypoint and local development setup.
5	 */
6	import postgres from 'postgres';
7	
8	export async function applyAuditTriggers(connectionString: string): Promise<void> {
9	  const client = postgres(connectionString, { max: 1 });
10	
11	  console.log('Applying audit immutability triggers...');
12	
13	  await client`
14	    CREATE OR REPLACE FUNCTION prevent_audit_log_mutation()
15	    RETURNS TRIGGER AS $$
16	    BEGIN
17	      RAISE EXCEPTION 'audit_logs table is immutable: % operations are forbidden', TG_OP;
18	      RETURN NULL;
19	    END;
20	    $$ LANGUAGE plpgsql
21	  `;
22	
23	  // Create triggers idempotently (drop-if-exists + create)
24	  await client`
25	    DO $$ BEGIN
26	      CREATE TRIGGER audit_logs_no_update
27	        BEFORE UPDATE ON audit_logs
28	        FOR EACH ROW EXECUTE FUNCTION prevent_audit_log_mutation();
29	    EXCEPTION WHEN duplicate_object THEN NULL;
30	    END $$
31	  `;
32	
33	  await client`
34	    DO $$ BEGIN
35	      CREATE TRIGGER audit_logs_no_delete
36	        BEFORE DELETE ON audit_logs
37	        FOR EACH ROW EXECUTE FUNCTION prevent_audit_log_mutation();
38	    EXCEPTION WHEN duplicate_object THEN NULL;
39	    END $$
40	  `;
41	
42	  console.log('Audit triggers applied.');
43	  await client.end();
44	}
45	
46	// Run directly
47	const dbUrl = process.env.DATABASE_URL;
48	if (dbUrl) {
49	  applyAuditTriggers(dbUrl).catch((err) => {
50	    console.error('Failed to apply audit triggers:', err);
51	    process.exit(1);
52	  });
53	}
