1	import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
2	import fp from 'fastify-plugin';
3	import { auditLogs } from '@studioops/db/schema';
4	
5	declare module 'fastify' {
6	  interface FastifyRequest {
7	    auditContext?: {
8	      resourceType: string;
9	      resourceId?: string;
10	      action?: string;
11	      beforeState?: unknown;
12	      afterState?: unknown;
13	    };
14	  }
15	}
16	
17	async function auditLogPlugin(fastify: FastifyInstance) {
18	  // Use onSend hook (before response body is sent) so we can fail-closed if audit write fails
19	  fastify.addHook('onSend', async (request: FastifyRequest, reply: FastifyReply, payload) => {
20	    // Only log requests to protected API routes (skip health, static, etc.)
21	    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
22	      return payload;
23	    }
24	
25	    // Log ALL protected-resource access including denials (401/403/404)
26	    // This ensures non-repudiation for both successful and denied access attempts
27	    const auditCtx = request.auditContext;
28	    const resourceType = auditCtx?.resourceType || inferResourceType(request.url);
29	    const action = auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`;
30	
31	    try {
32	      await fastify.db.insert(auditLogs).values({
33	        actorId: request.user?.sub || null,
34	        action,
35	        resourceType,
36	        resourceId: auditCtx?.resourceId || null,
37	        beforeState: auditCtx?.beforeState || null,
38	        afterState: auditCtx?.afterState || null,
39	        ipAddress: request.ip,
40	        userAgent: request.headers['user-agent'] || null,
41	      });
42	    } catch (err) {
43	      request.log.error({ err }, 'Failed to write audit log entry');
44	
45	      // Fail-closed: if audit can't be recorded, reject the response
46	      // This guarantees every protected-resource action is audited
47	      reply.code(503);
48	      return JSON.stringify({
49	        error: 'AUDIT_FAILURE',
50	        message: 'Operation could not be audited. Please retry.',
51	      });
52	    }
53	
54	    return payload;
55	  });
56	}
57	
58	function inferResourceType(url: string): string {
59	  const segments = url.replace('/api/v1/', '').split('/');
60	  return segments[0] || 'unknown';
61	}
62	
63	export default fp(auditLogPlugin, {
64	  name: 'audit-log',
65	  dependencies: ['database'],
66	  fastify: '5.x',
67	});
