}", "new_string": "async function auditLogPlugin(fastify: FastifyInstance) {
  // Use onResponse hook to audit all protected-resource access after the response is sent.
  // This avoids ERR_HTTP_HEADERS_SENT conflicts with Fastify's internal response pipeline.
  // Durability note: if the audit DB insert fails, the action was still recorded in the
  // application DB (same PostgreSQL instance), and the audit failure is logged to stderr.
  // The immutability triggers on audit_logs prevent tampering of existing entries.
  fastify.addHook('onResponse', async (request, reply) => {
    // Only log requests to protected API routes (skip health, static, etc.)
    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
      return;
    }

    // Log ALL protected-resource access including denials (401/403/404)
    const auditCtx = request.auditContext;
    const resourceType = auditCtx?.resourceType || inferResourceType(request.url);
    const action = auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`;

    try {
      await fastify.db.insert(auditLogs).values({
        actorId: request.user?.sub || null,
        action,
        resourceType,
        resourceId: auditCtx?.resourceId || null,
        beforeState: auditCtx?.beforeState || null,
        afterState: auditCtx?.afterState || null,
        ipAddress: request.ip,
        userAgent: request.headers['user-agent'] || null,
      });
    } catch (err) {
      // Log failure but don't crash — response is already sent
      request.log.error({ err }, 'CRITICAL: Failed to write audit log entry');
    }
  });
}"}

