4	async function errorHandlerPlugin(fastify: FastifyInstance) {
5	  fastify.setErrorHandler(function (
6	    error: FastifyError,
7	    request: FastifyRequest,
8	    reply: FastifyReply,
9	  ) {
10	    const statusCode = error.statusCode ?? 500;
11	
12	    if (statusCode >= 500) {
13	      request.log.error({ err: error }, 'Internal server error');
14	    } else {
15	      request.log.warn({ err: error, statusCode }, 'Client error');
16	    }
17	
18	    const response: { error: string; message: string; details?: unknown[] } = {
19	      error: statusCode >= 500 ? 'INTERNAL_SERVER_ERROR' : error.code ?? 'ERROR',
20	      message: statusCode >= 500 ? 'Internal Server Error' : error.message,
21	    };
22	
23	    if (error.validation) {
24	      response.error = 'VALIDATION_ERROR';
25	      response.message = 'Validation failed';
26	      response.details = error.validation;
27	    }
28	
29	    reply.status(statusCode).send(response);
30	  });
