1	import { FastifyInstance, FastifyRequest } from 'fastify';
2	import fp from 'fastify-plugin';
3	import rateLimit from '@fastify/rate-limit';
4	import { RATE_LIMITS } from '@studioops/shared';
5	
6	const multiplier = parseInt(process.env.RATE_LIMIT_MULTIPLIER || '0', 10);
7	const LIMIT_MULTIPLIER = multiplier > 0 ? multiplier : (process.env.NODE_ENV === 'test' ? 100 : 1);
8	
9	/**
10	 * Verified JWT identity extraction for rate-limit keying.
11	 * Uses Fastify's JWT verifier (cryptographic signature check).
12	 * Returns null on any failure — caller treats as guest.
13	 * Result is cached on the request to avoid repeated verification.
14	 */
15	async function getVerifiedIdentity(request: FastifyRequest): Promise<{ sub: string; role: string } | null> {
16	  // If auth middleware already ran, trust its result
17	  if (request.user?.sub) return request.user as { sub: string; role: string };
18	
19	  // Check cache from a previous rate-limit call on this request
20	  if ((request as any)._rateLimitIdentity !== undefined) return (request as any)._rateLimitIdentity;
21	
22	  const auth = request.headers.authorization;
23	  if (!auth?.startsWith('Bearer ')) {
24	    (request as any)._rateLimitIdentity = null;
25	    return null;
26	  }
27	
28	  try {
29	    // Full cryptographic verification via Fastify JWT plugin
30	    const decoded = request.server.jwt.verify<{ sub: string; role: string }>(auth.slice(7));
31	    (request as any)._rateLimitIdentity = decoded;
32	    return decoded;
33	  } catch {
34	    (request as any)._rateLimitIdentity = null;
35	    return null;
36	  }
37	}
38	
39	async function rateLimitPlugin(fastify: FastifyInstance) {
40	  await fastify.register(rateLimit, {
41	    max: async (request) => {
42	      const identity = await getVerifiedIdentity(request);
43	      if (identity?.role === 'administrator') return 999999;
44	      if (identity?.sub) return RATE_LIMITS.AUTHENTICATED * LIMIT_MULTIPLIER;
45	      return RATE_LIMITS.GUEST * LIMIT_MULTIPLIER;
46	    },
47	    timeWindow: RATE_LIMITS.WINDOW_MS,
48	    keyGenerator: async (request) => {
49	      const identity = await getVerifiedIdentity(request);
50	      if (identity?.sub) return `user:${identity.sub}`;
51	      return `guest:${request.ip}`;
52	    },
53	    errorResponseBuilder: (_request, context) => {
54	      return {
55	        error: 'TOO_MANY_REQUESTS',
56	        message: 'Rate limit exceeded',
57	        retryAfter: Math.ceil(context.ttl / 1000),
58	      };
59	    },
60	  });
61	}
62	
63	export default fp(rateLimitPlugin, {
64	  name: 'rate-limit',
65	  dependencies: ['auth'],
66	  fastify: '5.x',
67	});
