    const emptyState = page.locator('text=No portfolio items');
    const hasItems = await deleteBtn.isVisible().catch(() => false);
    const isEmpty = await emptyState.isVisible().catch(() => false);
    expect(hasItems || isEmpty).toBe(true);
  });
});
"}

