}", "new_string": "import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import fp from 'fastify-plugin';
import { auditLogs } from '@studioops/db/schema';

declare module 'fastify' {
  interface FastifyRequest {
    auditContext?: {
      resourceType: string;
      resourceId?: string;
      action?: string;
      beforeState?: unknown;
      afterState?: unknown;
    };
  }
}

const MAX_RETRY = 3;
const RETRY_DELAY_MS = 200;

function sleep(ms: number) { return new Promise(r => setTimeout(r, ms)); }

async function auditLogPlugin(fastify: FastifyInstance) {
  // Use onResponse hook to audit all protected-resource access.
  // Retries on transient failures to guarantee audit capture for compliance.
  fastify.addHook('onResponse', async (request, reply) => {
    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
      return;
    }

    const auditCtx = request.auditContext;
    const resourceType = auditCtx?.resourceType || inferResourceType(request.url);
    const action = auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`;

    const entry = {
      actorId: request.user?.sub || null,
      action,
      resourceType,
      resourceId: auditCtx?.resourceId || null,
      beforeState: auditCtx?.beforeState || null,
      afterState: auditCtx?.afterState || null,
      ipAddress: request.ip,
      userAgent: request.headers['user-agent'] || null,
    };

    // Retry loop for transient DB failures
    for (let attempt = 1; attempt <= MAX_RETRY; attempt++) {
      try {
        await fastify.db.insert(auditLogs).values(entry);
        return; // success
      } catch (err) {
        if (attempt < MAX_RETRY) {
          await sleep(RETRY_DELAY_MS * attempt);
          continue;
        }
        // All retries exhausted — log to stderr as structured JSON for external reconciliation
        request.log.fatal({
          err,
          auditEntry: entry,
          retriesExhausted: true,
        }, 'AUDIT_FAILURE: Failed to persist audit log after retries. Entry logged to stderr for reconciliation.');
      }
    }
  });
}"}

