declare module 'fastify' {
  interface FastifyRequest {
    auditContext?: {
      resourceType: string;
      resourceId?: string;
      action?: string;
      beforeState?: unknown;
      afterState?: unknown;
    };
    /** Set by audit plugin after successful DB insert */
    _auditRecorded?: boolean;
  }
}

const MAX_RETRY = 3;
const RETRY_DELAY_MS = 100;
const WRITE_METHODS = new Set(['POST', 'PUT', 'PATCH', 'DELETE']);

function sleep(ms: number) { return new Promise(r => setTimeout(r, ms)); }

async function insertAuditWithRetry(
  db: any,
  entry: Record<string, unknown>,
  log: any,
): Promise<boolean> {
  for (let attempt = 1; attempt <= MAX_RETRY; attempt++) {
    try {
      await db.insert(auditLogs).values(entry);
      return true;
    } catch (err) {
      if (attempt < MAX_RETRY) {
        await sleep(RETRY_DELAY_MS * attempt);
        continue;
      }
      log.fatal({ err, auditEntry: entry, retriesExhausted: true },
        'AUDIT_FAILURE: Failed to persist audit log after retries. Entry logged to stderr for reconciliation.');
      return false;
    }
  }
  return false;
}

async function auditLogPlugin(fastify: FastifyInstance) {
  // For WRITE operations (POST/PUT/PATCH/DELETE): use onSend to guarantee audit before response.
  // If audit fails after retries, replace the response with 503 (fail-closed for writes).
  fastify.addHook('onSend', async (request: FastifyRequest, reply: FastifyReply, payload) => {
    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
      return payload;
    }
    if (!WRITE_METHODS.has(request.method)) {
      return payload; // reads handled in onResponse
    }

    const auditCtx = request.auditContext;
    const entry = {
      actorId: request.user?.sub || null,
      action: auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`,
      resourceType: auditCtx?.resourceType || inferResourceType(request.url),
      resourceId: auditCtx?.resourceId || null,
      beforeState: auditCtx?.beforeState || null,
      afterState: auditCtx?.afterState || null,
      ipAddress: request.ip,
      userAgent: request.headers['user-agent'] || null,
    };

    const ok = await insertAuditWithRetry(fastify.db, entry, request.log);
    request._auditRecorded = ok;

    if (!ok && reply.statusCode < 400) {
      // Fail-closed: write action succeeded but audit couldn't be persisted
      reply.code(503);
      reply.header('content-type', 'application/json');
      return JSON.stringify({
        error: 'AUDIT_FAILURE',
        message: 'Operation could not be audited. Please retry.',
      });
    }

    return payload;
  });

  // For READ operations (GET/HEAD/OPTIONS): use onResponse (after response sent).
  // Reads are idempotent — the client can retry. We still want to log them for compliance.
  fastify.addHook('onResponse', async (request, reply) => {
    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
      return;
    }
    if (WRITE_METHODS.has(request.method)) {
      return; // already handled in onSend
    }

    const auditCtx = request.auditContext;
