  // For WRITE operations (POST/PUT/PATCH/DELETE): use onSend to guarantee audit before response.
  // If audit fails after retries, replace the response with 503 (fail-closed for writes).
  fastify.addHook('onSend', async (request: FastifyRequest, reply: FastifyReply, payload) => {
    if (!request.url.startsWith('/api/v1/') || request.url === '/api/v1/health') {
      return payload;
    }
    if (!WRITE_METHODS.has(request.method)) {
      return payload; // reads handled in onResponse
    }

    const auditCtx = request.auditContext;
    const entry = {
      actorId: request.user?.sub || null,
      action: auditCtx?.action || `${request.method} ${request.routeOptions?.url || request.url}`,
      resourceType: auditCtx?.resourceType || inferResourceType(request.url),
      resourceId: auditCtx?.resourceId || null,
      beforeState: auditCtx?.beforeState || null,
      afterState: auditCtx?.afterState || null,
      ipAddress: request.ip,
      userAgent: request.headers['user-agent'] || null,
    };

    await insertAuditWithRetry(fastify.db, entry, request.log);
    return payload;
  });

  // For READ operations (GET/HEAD/OPTIONS): use onResponse (after response sent).
  // Reads are idempotent — the client can retry. We still want to log them for compliance.
  fastify.addHook('onResponse', async (request, reply) => {
